INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-04-26', E'여호사밧의 시대 (역대하 19장)', E'역대하 19장', E'아합과 함께 길르앗 라못 전쟁에 참여했다가 생명의 위기에서 간신히 벗어난 여호사밧이 예루살렘으로 돌아옵니다. 평안히 궁으로 들어간 왕을 맞이한 것은 하나니의 아들 선견자 예후의 날카로운 질책이었습니다. "왕이 악한 자를 돕고 여호와를 미워하는 자들을 사랑하는 것이 옳으니이까"라는 예후의 말은 여호사밧의 동맹 정책이 하나님 보시기에 얼마나 잘못된 것인지를 분명히 보여줍니다. \n\n그러나 선견자는 질책만 하지 않고 여호사밧의 선한 면도 인정합니다. 아세라 목상들을 제거하고 마음을 다해 하나님을 찾은 그의 신앙적 열심을 하나님께서 기억하고 계신다는 것입니다. 이는 하나님의 공의로우신 평가를 보여주며, 동시에 여호사밧에게 회개와 개혁의 기회를 주시는 은혜였습니다.\n\n선견자의 질책을 겸허히 받아들인 여호사밧은 즉시 행동에 나섭니다. 브엘세바에서 에브라임 산지까지 백성들을 직접 찾아다니며 그들을 여호와께로 돌아오게 하는 영적 부흥 운동을 전개합니다. 더 나아가 그는 사법 개혁을 단행하여 각 성읍에 재판관을 세우고, 예루살렘에는 레위인과 제사장, 족장들로 구성된 최고 재판소를 설치합니다.\n\n특히 주목할 점은 재판관들에게 내린 그의 명령입니다. "너희가 재판하는 것이 사람을 위하여 할 것인지 여호와를 위하여 할 것인지를 잘 살피라"는 말씀은 모든 재판이 하나님 앞에서 이루어져야 함을 강조합니다. 불의와 편견, 뇌물이 없으신 하나님의 성품을 본받아 공정한 재판을 행하라는 이 가르침은 오늘날에도 여전히 유효한 정의의 원칙입니다.\n\n여호사밧의 개혁은 단순한 제도 개선이 아니었습니다. 그것은 하나님의 말씀에 기초한 영적 각성 운동이었고, 백성들이 하나님께 돌아오도록 이끄는 목회적 돌봄이었습니다. 실패를 통해 배우고, 질책을 통해 성장하며, 즉시 개혁으로 응답하는 여호사밧의 모습은 진정한 영적 지도자의 자세를 보여줍니다.', E'오늘의 핵심\n여호사밧은 선견자의 질책을 겸허히 받아들이고 즉시 영적 부흥 운동과 사법 개혁을 통해 백성들을 하나님께로 돌아오게 합니다.\n\n묵상 질문\n1. 하나님의 질책을 받을 때 나는 어떻게 반응하고 있나요?\n2. 내가 섬기는 자리에서 하나님의 공의를 실천하고 있습니까?\n3. 실패를 통해 배운 교훈을 어떻게 삶의 변화로 연결시킬 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-04-27', E'여호사밧의 시대 (역대하 20장)', E'역대하 20장', E'모압과 암몬의 연합군이 침공해 왔을 때, 여호사밧은 두려움 가운데서도 먼저 하나님께로 얼굴을 향합니다. 온 유다 백성과 함께 금식을 선포하고 여호와의 전 새 뜰에 모인 왕은 하나님의 주권과 약속을 붙들며 간절히 기도합니다. 그는 과거 하나님께서 이스라엘을 위해 행하신 일들을 기억하며, 지금 닥친 위기 앞에서도 오직 하나님만을 바라본다고 고백합니다. "우리를 치러 오는 이 큰 무리를 우리가 대적할 능력이 없고 어떻게 할 줄도 알지 못하옵고 오직 주만 바라보나이다"(대하 20:12)라는 그의 고백은 절체절명의 순간에 보여준 온전한 신앙의 모습입니다.\n\n하나님은 레위 사람 야하시엘을 통해 응답하십니다. 전쟁이 하나님께 속한 것이므로 두려워하지 말라는 위로와 함께, 싸우지 않고도 승리를 얻게 될 것이라는 놀라운 약속을 주십니다. 여호사밧과 백성들은 이 말씀을 믿고 찬양대를 군대 앞에 세워 행진합니다. 찬송이 시작될 때 하나님께서 적군들이 서로 치게 하셔서 자멸하게 하시는 기적을 경험합니다. 전쟁터가 찬양의 자리로, 두려움이 기쁨으로 바뀌는 하나님의 역사였습니다.\n\n그러나 역대기 기자는 여호사밧의 말년에 대한 아쉬움도 기록합니다. 하나님의 큰 은혜를 경험했음에도 불구하고 여전히 산당을 철거하지 않았고, 악한 이스라엘 왕 아하시야와 동맹을 맺어 배를 만드는 실수를 반복합니다. 엘리에셀 선지자의 책망대로 그 계획은 실패로 끝났습니다. 위기의 때에는 온전히 하나님을 의지했던 여호사밧이 평안할 때에는 타협적인 모습을 보인 것은, 신앙생활에서 일관성을 유지하는 것이 얼마나 어려운지를 보여줍니다. 하나님의 은혜를 경험한 후에도 끝까지 순종하며 살아가는 것이 참된 신앙의 과제임을 역대기는 우리에게 가르쳐 주고 있습니다.', E'오늘의 핵심\n여호사밧은 국가적 위기 앞에서 온전히 하나님을 의지하여 기적적인 승리를 경험했지만, 말년에는 여전히 타협적인 신앙의 모습을 보였습니다.\n\n묵상 질문\n1. 위기의 순간에 나는 무엇을 가장 먼저 의지하고 있나요?\n2. 하나님의 은혜를 경험한 후에도 여전히 내 삶에 남아있는 ''산당''은 무엇인가요?\n3. 찬양이 전쟁의 무기가 되었던 것처럼, 내 삶의 어려움 속에서 찬양의 능력을 경험해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-04-28', E'요아스와 여호야다의 개혁 (역대하 23장)', E'역대하 23장', E'여섯 해 동안 남유다는 아합과 이세벨의 딸 아달랴의 통치 아래서 우상숭배의 어둠에 빠져 있었습니다. 바알 숭배가 성행하고 다윗 왕가의 전통이 무너져가던 그때, 하나님께서는 제사장 여호야다를 통해 놀라운 개혁의 역사를 준비하고 계셨습니다. 여호야다는 아달랴의 학살에서 살아남은 어린 요아스를 6년간 성전에서 숨겨 키우며 때를 기다렸고, 마침내 제칠년에 용기를 내어 거사를 일으킵니다.\n\n여호야다의 개혁은 철저히 준비되고 질서 있게 진행되었습니다. 그는 먼저 백부장들과 언약을 맺고, 레위인들과 이스라엘 족장들을 모아 하나님의 전에서 왕과 언약을 세웁니다. 제사장들과 레위인들을 3분의 1씩 나누어 성전 문과 왕궁, 기초문을 지키게 하는 치밀한 계획은 이 일이 단순한 정변이 아니라 하나님의 거룩한 질서를 회복하는 신앙개혁임을 보여줍니다.\n\n요아스에게 면류관을 씌우고 율법책을 주는 대관식 장면은 의미심장합니다. 왕이 율법책을 받는다는 것은 그가 하나님의 말씀 아래서 통치해야 함을 상징합니다. "왕이여 만세 수를 누리소서"라는 백성들의 환호는 정당한 다윗 왕조의 회복에 대한 기쁨의 표현이었습니다. 이 모든 과정에서 여호야다는 성전의 거룩함을 지키려 애썼고, 아달랴조차도 성전이 아닌 왕궁 말문에서 처형되도록 했습니다.\n\n개혁은 정치적 차원을 넘어 신앙의 회복으로 이어집니다. 여호야다는 자기와 모든 백성과 왕 사이에 언약을 세워 "여호와의 백성이 되리라"고 선언합니다. 백성들은 바알 신당을 부수고 그 제사장을 죽였으며, 여호야다는 다윗이 정한 규례대로 성전 예배를 회복시킵니다. 레위 제사장들이 모세의 율법에 따라 번제를 드리며 즐거이 찬송하는 모습은 참된 예배의 회복을 보여줍니다.\n\n이 모든 개혁의 결과로 "그 땅의 모든 백성이 즐거워하고 성중이 평온하더라"는 기록은 하나님의 질서가 회복될 때 오는 참된 평화를 증거합니다. 한 사람의 신실한 제사장을 통해 무너진 신앙이 회복되고 나라가 새로워지는 은혜의 역사가 일어난 것입니다.', E'오늘의 핵심\n하나님께서는 신실한 제사장 여호야다를 통해 우상숭배로 타락한 남유다에 다윗 왕조를 회복시키시고, 성전 예배와 언약 백성의 정체성을 되찾게 하셨습니다.\n\n묵상 질문\n1. 여호야다처럼 때를 기다리며 신앙의 개혁을 준비하는 인내와 지혜가 내게 있나요?\n2. 우리 시대에 무너져가는 신앙의 전통과 가치를 회복하기 위해 나는 무엇을 할 수 있을까요?\n3. "여호와의 백성이 되리라"는 언약이 내 삶에서는 어떻게 구체화되고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-04-29', E'요아스와 여호야다의 개혁 (역대하 24장)', E'역대하 24장', E'남유다 역사에서 가장 극적인 개혁이 일어났습니다. 어린 나이에 왕위에 오른 요아스는 제사장 여호야다의 보호와 가르침 아래서 하나님 보시기에 정직한 왕으로 성장합니다. 아달랴의 폭정으로 무너진 성전을 보수하고자 하는 왕의 열정은 백성들의 마음을 움직였고, 자발적인 헌금으로 성전은 "이전 모양대로 견고하게" 회복되었습니다. 여호야다가 살아있는 동안 남유다는 하나님께 드리는 제사가 끊이지 않는 신앙의 황금기를 누렸습니다.\n\n그러나 한 사람의 영향력이 얼마나 중요한지를 보여주는 반전이 일어납니다. 130세를 일기로 여호야다가 세상을 떠나자, 요아스는 완전히 다른 사람이 되어버립니다. 유다 방백들의 아첨에 넘어간 왕은 조상들의 하나님 여호와의 전을 버리고 우상숭배에 빠집니다. 하나님께서는 선지자들을 보내 경고하셨지만, 요아스는 듣지 않았을 뿐만 아니라 자신을 책망하는 여호야다의 아들 스가랴를 성전 뜰에서 돌로 쳐죽이는 패역을 저지릅니다. 은인의 아들을 죽인 배은망덕한 왕의 최후는 비참했습니다. 작은 아람 군대에게 패하고, 신하들의 손에 암살당하며, 왕들의 묘실에도 들지 못하는 수치를 당합니다.\n\n요아스의 이야기는 신앙이 단지 환경의 산물이 아님을 가르쳐줍니다. 여호야다의 선한 영향력 아래서도, 그의 신앙은 뿌리를 내리지 못했습니다. 외적인 개혁은 있었지만 내면의 변화는 없었던 것입니다. 진정한 신앙은 누군가의 감독 아래서만 유지되는 것이 아니라, 하나님과의 인격적인 관계 속에서 자라나는 것임을 깨닫게 됩니다.', E'오늘의 핵심\n요아스의 극적인 변화는 외적 영향력에만 의존하는 신앙의 위험성을 보여주며, 하나님과의 진정한 관계가 얼마나 중요한지 일깨워줍니다.\n\n묵상 질문\n1. 나의 신앙은 누군가의 영향력에 의존하고 있지는 않은가요?\n2. 하나님께서 내게 주신 은혜를 기억하고 감사하며 살고 있나요?\n3. 신앙의 뿌리를 깊이 내리기 위해 오늘 무엇을 결단해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-04-30', E'요아스와 여호야다의 개혁 (역대하 25장)', E'역대하 25장', E'아마샤는 부왕 요아스를 죽인 신하들을 처형하면서도 그들의 자녀는 살려둡니다. 이는 모세 율법의 가르침을 따른 것으로, 각 사람이 자기 죄로 인해 죽어야 한다는 원칙을 지킨 것입니다. 왕위 초기에는 율법을 존중하는 모습을 보였던 아마샤였으나, 역대기 기자는 그가 "여호와께서 보시기에 정직하게 행하기는 하였으나 온전한 마음으로 행하지 아니하였더라"고 평가합니다. 이 평가는 곧 그의 통치 전체를 관통하는 예언이 되었습니다.\n\n아마샤는 에돔과의 전쟁을 앞두고 은 백 달란트로 북이스라엘의 용병 십만 명을 고용합니다. 그러나 하나님의 사람은 여호와께서 북이스라엘과 함께하지 않으신다며 이들을 돌려보낼 것을 권고합니다. 아마샤는 아까운 마음에도 불구하고 이 권고를 받아들여 북이스라엘 군대를 돌려보냅니다. 그 결과 하나님의 도우심으로 에돔과의 전쟁에서 승리를 거둡니다.\n\n그런데 승리 후 아마샤의 행동은 충격적입니다. 그는 패배한 에돔의 신상들을 가져와 자신의 신으로 섬기며 분향합니다. 자기 백성도 구원하지 못한 무력한 신들을 섬기는 모순된 행동에 대해 선지자가 책망하자, 아마샤는 오히려 선지자를 위협합니다. 하나님을 온전히 신뢰하지 못하는 그의 반쪽짜리 신앙이 여기서 드러납니다.\n\n교만해진 아마샤는 북이스라엘에 도전장을 보내지만, 오히려 크게 패하고 포로가 되어 예루살렘 성벽 일부가 헐리고 성전과 왕궁의 보물을 약탈당합니다. 에돔의 신들에게 절한 결과로 하나님께서 그를 대적의 손에 넘기신 것입니다. 결국 아마샤는 부왕처럼 반역으로 죽임을 당합니다. 온전하지 못한 신앙, 승리 후의 교만, 우상숭배가 그를 파멸로 이끈 것입니다.', E'오늘의 핵심\n아마샤의 불완전한 순종과 승리 후의 교만, 그리고 우상숭배는 결국 그를 패배와 죽음으로 이끌었습니다. 하나님은 온전한 마음으로 섬기는 신앙을 원하십니다.\n\n묵상 질문\n1. 나는 하나님을 온전한 마음으로 섬기고 있나요, 아니면 상황에 따라 타협하는 신앙을 가지고 있나요?\n2. 성공과 승리의 순간에 오히려 하나님을 잊고 교만해진 적은 없었나요?\n3. 내 삶에서 하나님보다 더 의지하고 있는 ''에돔의 신들''은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-01', E'웃시야 요담 아하스 시대 (역대하 26장)', E'역대하 26장', E'유다 백성은 열여섯 살의 웃시야를 왕으로 세웁니다. 어린 나이에 왕위에 오른 웃시야는 하나님 보시기에 정직하게 행하며, 하나님의 묵시를 밝히 아는 스가랴의 영적 지도를 받았습니다. 그가 여호와를 찾을 동안 하나님께서는 그를 형통하게 하셨고, 블레셋과 아라비아 사람들과의 전쟁에서 승리를 주셨습니다. 암몬 사람들이 조공을 바칠 정도로 웃시야의 명성은 애굽 변방까지 퍼져나갔습니다.\n\n웃시야는 국방을 강화하고 농업을 진흥시키는 탁월한 통치력을 보였습니다. 예루살렘 성벽을 견고히 하고 광야에 망대를 세웠으며, 물 웅덩이를 파서 목축업을 발전시켰습니다. 삼십만이 넘는 강한 군대를 조직하고 당시 최신 무기들을 개발하여 배치했습니다. 성경은 그가 "기이한 도우심을 얻어 강성하여졌다"고 기록합니다. 하나님의 특별한 은혜가 그와 함께했던 것입니다.\n\n그러나 강성함이 오히려 웃시야를 넘어뜨리는 원인이 되었습니다. 마음이 교만해진 그는 제사장만이 할 수 있는 분향을 자신이 직접 하려고 성전에 들어갔습니다. 아사랴를 비롯한 팔십 명의 제사장들이 용감하게 왕의 잘못을 지적했지만, 웃시야는 분노했습니다. 바로 그 순간 그의 이마에 나병이 나타났습니다. 하나님께서 직접 개입하신 것입니다. \n\n나병에 걸린 웃시야는 죽는 날까지 별궁에 격리되어 살았습니다. 오십이 년의 긴 통치 기간 중 대부분을 하나님과 동행하며 성공적으로 보냈지만, 교만으로 인한 한 번의 실수가 그의 말년을 비극으로 만들었습니다. 하나님께서 주신 형통함 속에서도 겸손을 잃지 않는 것이 얼마나 중요한지를 웃시야의 생애가 보여줍니다.', E'오늘의 핵심\n하나님을 찾는 동안 형통했던 웃시야는 강성해진 후 교만하여 하나님께서 정하신 경계를 넘었고, 그 결과 나병으로 심판받아 격리된 채 생을 마감했습니다.\n\n묵상 질문\n1. 웃시야가 하나님을 찾을 때와 교만해졌을 때의 차이는 우리에게 무엇을 가르쳐 주나요?\n2. 성공과 형통함 속에서도 하나님 앞에 겸손을 유지하려면 어떻게 해야 할까요?\n3. 내 삶에서 하나님이 정하신 경계를 넘으려는 교만한 마음은 없는지 돌아볼 때입니다.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-03', E'웃시야 요담 아하스 시대 (역대하 27장)', E'역대하 27장', E'남유다의 역사는 선한 왕과 악한 왕이 번갈아 나타나는 영적 롤러코스터와 같았습니다. 웃시야가 한센병으로 격리된 후 그의 아들 요담이 25세의 나이로 왕위에 올랐습니다. 역대기 기자는 요담이 아버지 웃시야의 모든 행위대로 여호와 보시기에 정직하게 행하였다고 평가합니다. 그러나 이 평가에는 중요한 단서가 붙어 있습니다. "여호와의 성전에는 들어가지 아니하였고"라는 구절이 그것입니다. 아버지가 성전에서 분향하다가 한센병에 걸린 일이 요담에게는 깊은 트라우마로 남았던 것 같습니다. 성전을 경외하는 마음은 좋았지만, 그것이 성전을 멀리하는 것으로 나타난 것은 안타까운 일이었습니다.\n\n더욱 심각한 문제는 "백성은 여전히 부패하였더라"는 기록입니다. 요담 개인은 하나님 앞에서 바른 길을 걸었지만, 백성들의 영적 상태는 계속 악화되고 있었습니다. 이는 지도자 한 사람의 개인적 신앙만으로는 한 나라 전체의 영적 흐름을 바꾸기 어렵다는 것을 보여줍니다. 요담은 16년간 통치하면서 많은 건축 사업을 진행했습니다. 성전의 윗문을 건축하고, 오벨 성벽을 증축하며, 산중에 성읍들을 세우고, 견고한 진영들과 망대를 건축했습니다. 암몬과의 전쟁에서도 승리하여 막대한 조공을 받았습니다.\n\n역대기 기자는 요담이 강성해진 이유를 명확하게 제시합니다. "요담이 그의 하나님 여호와 앞에서 바른 길을 걸었으므로 점점 강하여졌더라"는 것입니다. 이는 하나님과의 관계가 한 나라의 흥망성쇠를 결정한다는 역대기의 일관된 신학을 보여줍니다. 그러나 요담의 선한 통치에도 불구하고 백성들의 부패는 결국 다음 왕인 아하스 시대에 영적 재앙으로 나타나게 됩니다. 개인의 경건과 공동체의 신앙은 함께 가야 한다는 교훈을 남겨줍니다.', E'오늘의 핵심\n요담은 개인적으로 하나님 앞에서 바른 길을 걸어 강성해졌지만, 백성들의 영적 부패를 막지는 못했습니다. 지도자의 개인적 경건만으로는 공동체 전체의 영적 회복을 이루기 어렵다는 것을 보여줍니다.\n\n묵상 질문\n1. 아버지의 실패가 트라우마가 되어 성전을 멀리한 요담처럼, 나도 과거의 상처로 인해 하나님께 온전히 나아가지 못하는 부분이 있을까요?\n2. 요담이 하나님 앞에서 바른 길을 걸어 강성해진 것처럼, 내 삶의 형통함의 근원이 하나님과의 관계에 있음을 인정하고 있나요?\n3. 지도자는 바르게 살았지만 백성은 부패했던 것처럼, 내 주변 공동체의 영적 건강을 위해 내가 할 수 있는 일은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-04', E'웃시야 요담 아하스 시대 (역대하 28장)', E'역대하 28장', E'남유다의 역사에서 가장 어두운 장면 중 하나가 펼쳐집니다. 아하스가 스무 살에 왕위에 오르면서 유다는 영적으로 급속히 타락하기 시작합니다. 그의 조상 다윗과는 정반대의 길을 걸으며, 북이스라엘의 악한 왕들을 본받아 바알 우상을 만들어 섬겼습니다. 더욱 충격적인 것은 힌놈의 아들 골짜기에서 자기 자녀들을 불에 태워 제사하는 가증한 일까지 행했다는 사실입니다. 이는 하나님께서 가나안 민족을 심판하신 바로 그 죄악이었습니다.\n\n하나님의 심판은 즉각적으로 임했습니다. 아람과 북이스라엘의 침략으로 하루에만 십이만 명의 용사가 죽고, 이십만 명이 포로로 잡혀갔습니다. 그러나 이 비극 속에서도 하나님의 긍휼이 나타납니다. 북이스라엘의 선지자 오뎃과 지도자들이 나서서 유다 포로들을 돌려보내게 했던 것입니다. "너희의 형제들 중에서 사로잡아 온 포로를 놓아 돌아가게 하라"(대하 28:11)는 오뎃의 외침은 남북이 한 형제임을 일깨워주는 하나님의 음성이었습니다.\n\n그럼에도 아하스는 회개하지 않았습니다. 오히려 앗수르에게 도움을 요청하며 성전과 왕궁의 재물을 바쳤지만, 앗수르는 도움은커녕 유다를 공격했습니다. 곤경에 처할수록 아하스는 더욱 하나님을 거역했습니다. 다메섹의 신들에게 제사하고, 성전 문을 닫으며, 예루살렘 곳곳에 우상의 제단을 세웠습니다. 하나님을 의지하지 않고 인간적인 방법과 우상을 의지한 결과는 철저한 실패였습니다.\n\n아하스의 이야기는 신앙의 유산이 한 세대만에 무너질 수 있음을 보여줍니다. 경건한 조상들의 믿음도 개인의 선택 앞에서는 무력합니다. 각 사람은 하나님 앞에서 자신의 신앙을 선택하고 책임져야 합니다. 위기의 때일수록 하나님께 더 가까이 나아가야 하는데, 아하스는 정반대로 행했습니다. 그의 실패는 오늘 우리에게 경고의 메시지가 됩니다.', E'오늘의 핵심\n아하스는 위기 앞에서 하나님을 버리고 우상과 세상 권력을 의지했으나, 그 결과는 더 큰 재앙과 실패였습니다. 곤경 속에서도 하나님께 돌아가지 않는 완악함이 그를 파멸로 이끌었습니다.\n\n묵상 질문\n1. 어려움을 만날 때 나는 먼저 하나님께 나아가나요, 아니면 인간적인 해결책부터 찾나요?\n2. 신앙의 유산을 물려받았다면, 그것을 나의 개인적 신앙으로 만들고 있나요?\n3. 실패와 곤경이 오히려 하나님과 멀어지게 만드는 것은 아닌지 점검해볼 필요가 있지 않을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-05', E'히스기야의 개혁정치 (역대하 29장)', E'역대하 29장', E'아하스의 뒤를 이어 왕위에 오른 히스기야가 첫 번째로 착수한 일은 하나님의 전을 성결하게 하는 일이었습니다. 아버지 아하스가 16년간 우상숭배로 나라를 어둠 속에 빠뜨렸던 것과는 정반대의 길이었습니다. 25세의 젊은 왕은 즉위 첫 달에 곧바로 닫혔던 성전 문을 열고 수리하기 시작합니다. 제사장들과 레위인들을 불러 모은 히스기야는 남유다가 처한 비참한 현실을 직시합니다. 조상들이 하나님을 버리고 성전을 등졌기에 백성들이 칼에 쓰러지고 자녀와 아내들이 포로로 잡혀갔다는 것입니다.\n\n히스기야는 레위인들에게 "내 아들들아 이제는 게으르지 말라"(대하 29:11)고 격려하며 성전 정화 작업을 명령합니다. 이 말에 레위인들이 즉각 응답하여 16일간의 대대적인 정화 작업이 시작됩니다. 제사장들은 성전 안으로 들어가 모든 더러운 것을 끌어내고, 레위인들은 그것을 받아 기드론 시내로 가져갔습니다. 아하스가 버렸던 성전 기구들도 다시 정돈하고 성결하게 하여 제자리에 놓았습니다.\n\n성전 정화가 끝나자 히스기야는 곧바로 속죄제와 번제를 드립니다. 수송아지와 숫양, 어린 양과 숫염소를 각각 일곱 마리씩 준비하여 나라와 성소와 유다를 위한 속죄제물로 삼았습니다. 다윗 시대의 찬양대를 복원하여 제금과 비파와 수금으로 여호와를 찬송하게 했고, 제사장들은 나팔을 불었습니다. 온 회중이 함께 경배하며 즐거움으로 찬송했고, 자원하여 제물과 감사제물을 가져왔습니다. 놀랍게도 레위인들의 헌신이 제사장들보다 더 성심이 있었다고 기록되어 있습니다. 이렇게 여호와의 전에서 섬기는 일이 순서대로 갖추어지자, 히스기야와 백성들은 하나님께서 이 일을 예비하셨음을 깨닫고 기뻐했습니다.', E'오늘의 핵심\n히스기야는 즉위하자마자 닫혔던 성전 문을 열고 대대적인 정화 작업을 통해 예배를 회복함으로써, 우상숭배로 어두웠던 남유다에 영적 개혁의 서막을 열었습니다.\n\n묵상 질문\n1. 히스기야가 왕이 되어 가장 먼저 성전을 정화한 이유는 무엇일까요?\n2. 내 삶에서 하나님과의 관계를 가로막는 ''더러운 것''들은 무엇인가요?\n3. 레위인들처럼 성심을 다해 하나님을 섬기려면 어떤 결단이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-06', E'히스기야의 개혁정치 (역대하 30장)', E'역대하 30장', E'히스기야가 성전을 정결하게 한 후 착수한 일은 오랫동안 제대로 지켜지지 못했던 유월절을 회복하는 것이었습니다. 왕은 남유다뿐 아니라 북이스라엘 지역인 에브라임과 므낫세에까지 편지를 보내어 예루살렘으로 와서 유월절을 지키자고 초청합니다. 이는 이미 앗수르에 의해 멸망한 북이스라엘의 남은 백성들까지 포용하려는 히스기야의 넓은 마음을 보여줍니다.\n\n보발꾼들이 전한 메시지는 단순한 절기 준수의 권면이 아니었습니다. "너희는 아브라함과 이삭과 이스라엘의 하나님 여호와께로 돌아오라"(대하 30:6)는 회개의 촉구였으며, 조상들의 실패를 반면교사로 삼아 하나님께 돌아오라는 간절한 호소였습니다. 비록 많은 이들이 이 초청을 조롱하고 비웃었지만, 아셀과 므낫세와 스불론 중 일부는 겸손한 마음으로 예루살렘에 올라왔습니다.\n\n유월절 준비가 완벽하지는 않았습니다. 많은 백성이 정결 예식을 제대로 거치지 못한 채 유월절 양을 먹었고, 이는 율법을 어기는 일이었습니다. 그러나 히스기야는 이들을 위해 중보기도를 드렸습니다. 그는 형식적 정결보다 하나님을 향한 진실한 마음이 더 중요함을 알았던 것입니다. 여호와께서는 왕의 기도를 들으시고 백성을 고치셨습니다.\n\n이렇게 시작된 유월절은 큰 기쁨의 축제가 되었습니다. 원래 7일간 지키는 절기였지만 백성들은 너무나 즐거워서 7일을 더 지키기로 결의했습니다. 솔로몬 시대 이후로 이런 기쁨이 예루살렘에 없었다고 기록될 정도로, 하나님과의 관계 회복은 넘치는 기쁨을 가져다주었습니다. 제사장과 레위인들의 축복의 소리가 하늘에 상달되었다는 표현은 하나님께서 이 모든 예배를 기쁘게 받으셨음을 보여줍니다.', E'오늘의 핵심\n히스기야는 남북을 아우르는 유월절 회복을 통해 분열된 백성을 하나로 모으고, 형식보다 마음을 중시하는 참된 예배의 기쁨을 경험하게 했습니다.\n\n묵상 질문\n1. 하나님께로 돌아오라는 초청을 거절하거나 조롱하는 마음이 내 안에는 없나요?\n2. 종교적 형식과 규례를 지키는 것과 진실한 마음으로 하나님을 찾는 것 중 무엇이 더 중요할까요?\n3. 하나님과의 관계 회복이 가져다주는 기쁨을 최근에 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-07', E'히스기야의 개혁정치 (역대하 31장)', E'역대하 31장', E'유월절 축제가 끝나자 백성들의 마음에 놀라운 변화가 일어났습니다. 거기 모였던 이스라엘 무리가 자발적으로 나가서 유다와 베냜민, 에브라임과 므낫세 온 땅의 주상들과 아세라 목상을 부수고 산당과 제단들을 완전히 제거했습니다. 히스기야가 명령하기 전에 백성들이 스스로 우상을 척결한 것은 하나님을 향한 그들의 마음이 진심으로 회복되었음을 보여줍니다.\n\n히스기야는 이제 하나님께 드리는 예배가 지속적으로 이루어질 수 있도록 제도적 기반을 마련합니다. 제사장과 레위인들의 반열을 정하고 각자의 직무를 명확히 하여, 번제와 화목제를 드리며 성전에서 감사와 찬송이 끊이지 않게 했습니다. 또한 왕의 재산에서 정기적인 번제 비용을 충당하고, 백성들에게는 제사장과 레위인들의 생활을 책임지도록 했습니다. 이는 그들이 생계 걱정 없이 여호와의 율법을 힘써 지킬 수 있게 하려는 배려였습니다.\n\n왕의 명령이 내려지자 백성들의 반응은 즉각적이고도 넘치는 것이었습니다. 곡식과 포도주, 기름과 꿀 등 밭에서 나는 모든 소산의 첫 열매를 풍성히 드렸고, 십일조도 많이 가져왔습니다. 셋째 달부터 일곱째 달까지 계속해서 예물이 쌓여 여러 더미를 이루었습니다. 대제사장 아사랴는 "백성이 예물을 여호와의 전에 드리기 시작함으로부터 우리가 만족하게 먹었으나 남은 것이 많으니 이는 여호와께서 그의 백성에게 복을 주셨음이라"(대하 31:10)고 증언합니다.\n\n히스기야는 넘치는 예물을 체계적으로 관리하기 위해 성전에 창고를 준비하고, 신실한 레위인들을 책임자로 세워 공정하게 분배하도록 했습니다. 제사장과 레위인뿐 아니라 그들의 가족들까지 빠짐없이 돌보았고, 성읍 밖에 사는 이들도 놓치지 않았습니다. 이러한 히스기야의 개혁은 선과 정의와 진실함으로 이루어졌고, 그가 한 마음으로 하나님을 찾고 섬겼기에 모든 일이 형통했습니다. 진정한 영적 부흥은 예배의 회복과 함께 삶의 모든 영역에서 하나님의 뜻을 구하고 실천할 때 열매를 맺게 됩니다.', E'오늘의 핵심\n히스기야의 개혁은 백성들의 자발적인 우상 제거와 넘치는 헌신으로 이어졌고, 체계적인 성전 운영을 통해 지속가능한 예배 공동체를 세워갔습니다.\n\n묵상 질문\n1. 하나님께서 내 삶에 부어주신 넘치는 은혜를 어떻게 감사로 표현하고 있나요?\n2. 나는 하나님의 일을 위해 물질과 시간을 기쁘게 드리고 있나요?\n3. 히스기야처럼 한 마음으로 하나님을 찾으며 모든 일을 행하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-08', E'히스기야의 회개와 므낫세의 죄악 (역대하 32장)', E'역대하 32장', E'앗수르의 대군이 유다를 향해 밀려오는 절체절명의 순간, 히스기야는 인간적인 대비와 함께 더 중요한 영적 준비를 했습니다. 물 근원을 막고 성벽을 보수하며 무기를 만들었지만, 그의 진짜 무기는 하나님께 대한 신뢰였습니다. "우리와 함께 하시는 이는 우리의 하나님 여호와시라 반드시 우리를 도우시고 우리를 대신하여 싸우시리라"(대하 32:8). 이 선포는 백성들에게 큰 위로가 되었고, 실제로 하나님께서는 천사를 보내어 앗수르 군대를 멸하심으로써 히스기야의 믿음이 헛되지 않았음을 증명하셨습니다.\n\n그런데 위기가 지나고 평안과 번영이 찾아오자 히스기야에게 예상치 못한 시험이 찾아왔습니다. 죽을 병에서 기적적으로 회복되고, 열방이 보물을 바치며 존귀하게 여기는 상황에서 그의 마음에 교만이 싹튼 것입니다. 특히 바벨론 사신들에게 왕실의 모든 보물을 자랑스럽게 보여준 일은, 하나님보다 자신의 부와 영광을 의지하기 시작했음을 보여줍니다. 다행히 히스기야는 자신의 교만을 깨닫고 회개했고, 하나님께서는 그 겸손함을 받으셨습니다.\n\n히스기야의 이야기는 우리에게 중요한 교훈을 전해줍니다. 위기의 때에는 간절히 하나님을 찾다가도, 형편이 나아지면 은혜를 잊어버리는 것이 우리의 연약함입니다. 물질적 풍요, 사회적 인정, 건강의 회복 같은 축복이 오히려 하나님으로부터 멀어지게 하는 덫이 될 수 있음을 본문은 경고합니다. 진정한 신앙의 성숙은 어려울 때만이 아니라 평안할 때에도 하나님을 기억하고, 받은 은혜에 합당하게 반응하는 것입니다. 오늘 우리의 삶 속에서 감사와 겸손으로 보답해야 할 하나님의 은혜는 무엇인지 돌아보아야 하겠습니다.', E'오늘의 핵심\n히스기야는 국가적 위기 앞에서 하나님을 온전히 신뢰했으나, 평안과 번영 속에서는 교만에 빠졌다가 다시 회개함으로써 신앙의 성숙을 보여주었습니다.\n\n묵상 질문\n1. 내가 지금 당면한 어려움 속에서 인간적인 해결책과 함께 하나님을 먼저 의지하고 있나요?\n2. 형편이 나아진 후에도 그 은혜의 근원이신 하나님을 기억하고 감사하며 살고 있나요?\n3. 히스기야처럼 내 마음의 교만을 인정하고 겸손히 돌이킬 용기가 있는지 점검해 보세요.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-10', E'히스기야의 회개와 므낫세의 죄악 (역대하 33장)', E'역대하 33장', E'히스기야의 신앙 개혁이 유다를 구원으로 이끌었던 그 시대가 막을 내리고, 열두 살의 어린 므낫세가 왕위에 올랐습니다. 그런데 놀랍게도 므낫세는 아버지가 평생 헐어버렸던 산당을 다시 세우고, 바알 제단을 쌓으며, 하늘의 일월성신을 섬기기 시작합니다. 더욱 충격적인 것은 하나님의 성전 안에까지 우상의 제단을 세웠다는 사실입니다. 하나님께서 "내가 내 이름을 예루살렘에 영원히 두리라"(대하 33:4)고 약속하신 바로 그 성전이 우상으로 더럽혀진 것입니다.\n\n므낫세의 악행은 여기서 그치지 않았습니다. 힌놈의 아들 골짜기에서 자기 아들들을 불 가운데로 지나가게 하는 인신제사를 행하고, 점술과 사술에 빠져들었습니다. 성경은 그가 백성을 꾀어 악을 행하게 했는데, 그 정도가 여호와께서 멸하신 가나안 족속들보다 더 심했다고 기록합니다. 한 세대 만에 이스라엘이 가나안 족속보다 더 악해진 것입니다.\n\n하나님께서는 므낫세와 백성들에게 경고하셨지만 그들은 듣지 않았습니다. 결국 하나님은 앗수르 군대를 통해 므낫세를 징계하십니다. 쇠사슬에 묶여 바벨론으로 끌려간 므낫세는 그제야 환난 중에 하나님께 간구하며 크게 겸손해집니다. 놀랍게도 하나님은 이 악한 왕의 기도까지도 들으시고 그를 예루살렘으로 돌아오게 하십니다. "므낫세가 그제서야 여호와께서 하나님이신 줄을 알았더라"(대하 33:13)는 고백이 우리에게 깊은 울림을 줍니다.\n\n돌아온 므낫세는 우상을 제거하고 여호와의 제단을 보수하며 백성들에게 하나님을 섬기라고 명령합니다. 비록 백성들이 여전히 산당에서 제사를 드리는 한계는 있었지만, 적어도 여호와께만 제사를 드리게 되었습니다. 그러나 므낫세의 아들 아몬은 아버지의 악행만을 본받고 회개는 본받지 않았습니다. 겸손하지 않고 더욱 범죄하다가 신하들의 반역으로 죽임을 당합니다.\n\n이 본문은 하나님의 놀라운 은혜와 인간의 책임을 동시에 보여줍니다. 가장 악한 왕조차도 진심으로 회개할 때 용서하시는 하나님의 긍휼하심과, 그럼에도 불구하고 55년간 쌓인 악의 영향력이 쉽게 사라지지 않는 현실을 함께 보여주는 것입니다. 오늘 우리의 선택이 다음 세대에 어떤 유산을 남길지, 진지하게 생각해 보아야 할 때입니다.', E'오늘의 핵심\n므낫세는 아버지 히스기야의 모든 개혁을 무너뜨리고 극악한 우상숭배를 행했지만, 환난 중에 회개하여 하나님의 용서를 받았습니다. 그러나 그의 악행이 남긴 영향은 다음 세대까지 이어졌습니다.\n\n묵상 질문\n1. 므낫세처럼 하나님의 은혜를 경험한 부모 세대의 신앙이 자녀에게 전달되지 않는 이유는 무엇일까요?\n2. 환난 중에야 비로소 하나님을 찾게 되는 우리의 연약함을 어떻게 극복할 수 있을까요?\n3. 내가 지금 행하는 일들이 다음 세대에 어떤 영향을 미칠지 기도하며 점검해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-11', E'다시 태어나는 공동체, 재건세대 (에스라 1장)', E'에스라 1장', E'하나님의 백성이 바빌론에 포로로 끌려간 지 70년의 세월이 흘렀습니다. 예레미야를 통해 약속하신 그 기간이 정확히 채워졌을 때, 놀라운 일이 일어납니다. 이방 제국의 왕 고레스가 "하늘의 하나님 여호와께서 세상 모든 나라를 내게 주셨고 나에게 명령하사 유다 예루살렘에 성전을 건축하라 하셨나니"(스 1:2)라고 선포한 것입니다. 하나님께서는 이방 왕의 마음을 감동시켜 당신의 뜻을 이루어 가십니다.\n\n고레스의 조서는 단순히 귀환 허락에 그치지 않았습니다. 그는 유대인들이 예루살렘으로 돌아가 성전을 재건하도록 명령하며, 주변 사람들이 은과 금과 물품으로 그들을 도우라고까지 지시합니다. 더욱 놀라운 것은 느부갓네살이 예루살렘 성전에서 약탈해 간 성전 기물들을 모두 돌려주었다는 사실입니다. 금과 은으로 된 그릇 5,400개가 유다 총독 세스바살에게 인계되어 예루살렘으로 운반됩니다.\n\n이 귀환의 물결에 누가 동참했을까요? 에스라는 "그 마음이 하나님께 감동을 받고 올라가서 예루살렘에 여호와의 성전을 건축하고자 하는 자가 다 일어나니"라고 기록합니다. 바빌론에서 이미 정착하여 안정된 삶을 누리던 많은 이들이 있었을 것입니다. 그러나 하나님의 감동하심을 받은 이들은 기득권을 포기하고 황폐한 고국으로 돌아가는 길을 선택했습니다. 유다와 베냐민 족장들, 제사장들과 레위인들이 앞장섰고, 일반 백성들도 합류했습니다.\n\n70년이라는 긴 포로 생활은 이스라엘 백성에게 깊은 영적 성찰의 시간이 되었습니다. 그들은 우상숭배와 불순종의 결과가 무엇인지 뼈저리게 경험했고, 이제 하나님께서 주시는 새로운 기회 앞에 서게 되었습니다. 고레스라는 이방 왕을 통해서라도 당신의 백성을 회복시키시는 하나님의 신실하심과 주권적 역사가 에스라 1장에 생생히 드러납니다.', E'오늘의 핵심\n하나님께서는 정하신 때에 이방 왕 고레스의 마음을 감동시켜 포로 된 백성을 귀환시키시고, 성전 재건의 새로운 장을 여십니다.\n\n묵상 질문\n1. 70년의 약속을 정확히 지키시는 하나님의 신실하심을 어떻게 경험하고 계신가요?\n2. 안정된 삶을 포기하고 하나님의 일에 동참한 사람들처럼, 당신은 무엇을 결단해야 합니까?\n3. 하나님께서 뜻밖의 사람과 방법으로 일하실 때, 그것을 알아볼 영적 민감함이 있으신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-12', E'다시 태어나는 공동체, 재건세대 (에스라 2장)', E'에스라 2장', E'방대한 귀환자 명단이 에스라 2장에 빼곡히 기록되어 있습니다. 바벨론 포로 생활 70년을 마치고 고국으로 돌아가는 42,360명의 이름과 숫자가 하나하나 새겨져 있는 것입니다. 이 명단은 단순한 인구 통계가 아니라, 하나님의 신실하신 약속 이행의 증거이며, 믿음을 지킨 사람들의 거룩한 기록입니다. \n\n스룹바벨과 예수아의 인도 아래 귀환하는 이들 중에는 제사장들과 레위인들, 성전 봉사자들과 일반 백성들이 모두 포함되어 있었습니다. 특별히 주목할 점은 이들이 각자의 조상의 고향과 성읍을 정확히 기억하고 있었다는 사실입니다. 70년이라는 긴 세월 동안 바벨론에서 태어나고 자란 2, 3세대들임에도 불구하고, 그들은 자신들의 정체성과 뿌리를 잊지 않았던 것입니다.\n\n하나님께서는 이 귀환자 명단을 통해 우리에게 중요한 진리를 보여주십니다. 하나님은 당신의 백성 한 사람 한 사람을 기억하고 계시며, 그들의 이름을 아신다는 것입니다. "온 회중의 합계가 사만 이천삼백육십 명"(스 2:64)이라는 기록은 하나님께서 얼마나 정확하게 당신의 백성을 세고 계시는지를 보여줍니다.\n\n귀환 공동체 가운데는 자신의 계보를 증명할 수 없어 제사장 직무에서 제외된 사람들도 있었습니다. 이는 하나님의 거룩한 직무를 수행하는 데 있어서 정체성의 확실함이 얼마나 중요한지를 보여주는 대목입니다. 동시에 이들은 우림과 둠밈을 가진 제사장이 일어날 때까지 기다리라는 지시를 받았는데, 이는 하나님께서 때가 되면 모든 것을 분명히 하실 것이라는 소망을 품게 합니다.\n\n귀환자들이 예루살렘 성전 터에 도착했을 때, 그들은 자발적으로 성전 재건을 위한 예물을 드렸습니다. 금 육만 천 다릭과 은 오천 마네, 그리고 제사장의 옷 백 벌은 그들이 바벨론에서 어렵게 모은 재산이었을 것입니다. 그러나 그들은 기쁨으로 이를 드렸는데, 이는 하나님의 성전 재건이라는 거룩한 사명 앞에서 개인의 소유를 아끼지 않는 헌신의 모습을 보여줍니다.', E'오늘의 핵심\n하나님은 당신의 백성 한 사람 한 사람의 이름을 기억하시며, 포로 생활을 끝내고 귀환하는 42,360명의 명단을 통해 신실하신 언약의 성취를 보여주십니다.\n\n묵상 질문\n1. 70년의 포로 생활에도 정체성을 잃지 않은 귀환자들처럼, 나는 하나님의 백성으로서의 정체성을 어떻게 지키고 있나요?\n2. 하나님께서 내 이름을 기억하고 계신다는 사실이 오늘 나에게 어떤 위로와 힘이 되나요?\n3. 성전 재건을 위해 기쁨으로 헌금한 귀환자들처럼, 나는 하나님의 일에 어떤 마음으로 참여하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-13', E'성전 건축의 기초를 놓다 (에스라 3장)', E'에스라 3장', E'일곱째 달이 되었습니다. 예루살렘에 도착한 귀환 공동체가 가장 먼저 한 일은 하나님의 제단을 세우는 것이었습니다. 대제사장 예수아와 총독 스룹바벨의 인도로 백성들은 모세의 율법에 기록된 대로 제단을 만들고 번제를 드리기 시작합니다. 70년의 포로 생활 동안 중단되었던 예배가 다시 시작된 것입니다. \n\n귀환 공동체는 주변 민족들을 두려워하면서도 제단을 세우고 아침저녁으로 번제를 드렸습니다. 초막절을 지키고, 정해진 절기마다 제사를 드리며, 자원하는 예물을 바쳤습니다. 비록 성전의 기초도 놓지 못한 상황이었지만, 그들에게는 먼저 하나님께 예배드리는 일이 우선이었습니다.\n\n이듬해 둘째 달, 드디어 성전 재건 공사가 시작됩니다. 스룹바벨과 예수아를 중심으로 모든 백성이 힘을 모았고, 이십 세 이상의 레위인들이 공사를 감독했습니다. 건축자들이 성전의 기초를 놓을 때, 제사장들은 예복을 입고 나팔을 불었으며, 레위인들은 제금을 들고 다윗이 정한 규례대로 여호와를 찬송했습니다.\n\n"주는 지극히 선하시므로 그의 인자하심이 이스라엘에게 영원하시도다"(스 3:11)라는 찬양이 울려 퍼졌습니다. 그러나 이 감격의 순간에도 복잡한 감정이 교차했습니다. 젊은 세대는 기쁨으로 크게 함성을 질렀지만, 솔로몬 성전의 영광을 기억하는 노인들은 초라한 기초를 보며 대성통곡했습니다. 기쁨의 함성과 슬픔의 통곡이 뒤섞여 멀리까지 들렸습니다.\n\n하나님의 백성이 예배를 회복하는 모습은 우리에게 중요한 교훈을 줍니다. 그들은 어려운 환경 속에서도, 성전 건물이 없는 상황에서도 먼저 제단을 세우고 예배를 드렸습니다. 이것이 바로 신앙 공동체가 회복되는 출발점이었습니다.', E'오늘의 핵심\n포로에서 돌아온 백성들은 성전 건물보다 먼저 제단을 세우고 예배를 회복했으며, 기초를 놓으며 하나님의 인자하심을 찬양했습니다.\n\n묵상 질문\n1. 어려운 상황 속에서도 예배를 우선순위에 두는 신앙을 가지고 있나요?\n2. 과거의 영광에 얽매이지 않고 현재 하나님이 행하시는 일에 감사하고 있나요?\n3. 우리 공동체가 회복해야 할 예배의 본질은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-14', E'성전 건축의 기초를 놓다 (에스라 4장)', E'에스라 4장', E'귀환 공동체가 성전 재건의 기초를 놓자, 그 땅에 살고 있던 대적들이 나타나기 시작합니다. 이들은 앗수르 왕 에살핫돈 시대에 북이스라엘 멸망 후 사마리아 지역으로 이주된 이방인들과 그 후손들이었습니다. 그들은 스룹바벨과 족장들에게 접근하여 함께 성전을 건축하자고 제안합니다. 겉으로는 같은 하나님을 섬긴다고 주장했지만, 실상은 여호와 신앙과 이방 종교를 혼합한 혼합주의 신앙을 가진 사람들이었습니다.\n\n스룹바벨과 예수아는 단호하게 거절합니다. 하나님의 성전은 순수한 신앙 공동체에 의해 건축되어야 했기 때문입니다. 이 거절로 인해 대적들의 본심이 드러납니다. 그들은 유다 백성의 손을 약하게 하여 건축을 방해하고, 페르시아 관리들에게 뇌물을 주어 성전 건축 계획을 막습니다. 더 나아가 아닥사스다 왕에게 거짓 보고서를 올려 귀환 공동체가 성전이 아닌 성벽을 재건하여 반역을 꾀한다고 모함합니다.\n\n대적들의 교묘한 전략은 효과를 거둡니다. 페르시아 왕은 예루살렘의 과거 역사를 조사하고, 이 도시가 왕들에게 반역했던 전력이 있음을 확인한 후 공사 중단 명령을 내립니다. 르훔과 심새는 왕의 조서를 받자마자 예루살렘으로 급히 달려가 권력으로 공사를 중단시킵니다. 이렇게 하나님의 성전 재건 사업은 다리오 왕 2년까지 약 16년간 중단되고 맙니다.\n\n이 과정은 하나님의 일을 할 때 만나게 되는 영적 전투의 실상을 보여줍니다. 대적들은 처음에는 협력을 가장하여 접근하고, 거절당하면 직접적인 방해와 정치적 모함으로 하나님의 일을 막으려 합니다. 그러나 하나님께서는 이 모든 방해에도 불구하고 당신의 뜻을 이루어 가십니다. 중단된 성전 건축은 하나님께서 정하신 때에 학개와 스가랴 선지자를 통해 다시 시작될 것입니다.', E'오늘의 핵심\n하나님의 성전 재건을 방해하는 대적들의 교묘한 전략으로 공사가 중단되지만, 이는 하나님의 일을 하는 과정에서 겪게 되는 영적 전투의 한 단면입니다.\n\n묵상 질문\n1. 순수한 신앙을 지키기 위해 때로는 단호한 거절이 필요한 순간이 있지 않을까요?\n2. 하나님의 일을 방해하는 세력들 앞에서 낙심하지 않으려면 무엇이 필요할까요?\n3. 중단된 것처럼 보이는 하나님의 일도 하나님의 때에 다시 시작될 것을 믿고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-15', E'성전 재건의 기쁨 (에스라 5장)', E'에스라 5장', E'오랜 침묵의 시간이 끝나고 하나님께서 다시 역사하십니다. 성전 재건이 중단된 지 16년, 백성들은 자신들의 집을 짓느라 바빴고 하나님의 집은 폐허로 남아 있었습니다. 그런데 다리오 왕 제2년, 선지자 학개와 스가랴가 하나님의 말씀을 선포하기 시작합니다. 이들의 예언은 단순한 책망이 아니라 하나님의 백성을 다시 일으켜 세우는 격려의 메시지였습니다.\n\n스룹바벨과 예수아는 선지자들의 말씀에 즉시 반응합니다. 그들이 성전 재건을 다시 시작하자, 유브라데 강 건너편 총독 닷드내와 그의 동료들이 찾아와 추궁합니다. "누가 너희에게 명령하여 이 성전을 건축하게 하였느냐?" 이전에도 이런 방해로 공사가 중단되었기에 백성들은 두려워할 수 있었습니다. \n\n그러나 이번에는 달랐습니다. 성경은 "하나님이 유다 장로들을 돌보셨으므로"(스 5:5)라고 기록합니다. 하나님의 특별한 보호하심이 그들과 함께했기에 총독들도 함부로 공사를 중단시킬 수 없었습니다. 오히려 그들은 다리오 왕에게 보고서를 올려 왕의 답변을 기다리게 됩니다.\n\n유다 장로들의 대답은 그들의 정체성과 사명을 분명히 보여줍니다. "우리는 천지의 하나님의 종이라"는 고백은 페르시아 제국의 권세 앞에서도 흔들리지 않는 신앙의 선언이었습니다. 그들은 조상들이 하나님을 노엽게 하여 성전이 파괴되고 포로가 되었던 역사를 정직하게 인정하면서도, 고레스 왕의 칙령에 따라 성전을 재건하고 있음을 당당히 밝힙니다.\n\n총독들이 올린 보고서는 공정하고 사실적이었습니다. 이들은 유다 백성의 주장을 그대로 전달하며 왕에게 고레스의 칙령을 확인해 볼 것을 제안합니다. 하나님께서는 방해하려던 자들의 보고서마저도 성전 재건을 돕는 도구로 사용하셨습니다. 16년 전의 좌절이 이제는 더 확실한 보장으로 바뀌어가고 있었습니다.', E'오늘의 핵심\n하나님께서는 선지자들의 격려와 특별한 보호하심으로 중단되었던 성전 재건 사역을 다시 시작하게 하시고, 방해하는 자들조차 하나님의 뜻을 이루는 도구로 사용하십니다.\n\n묵상 질문\n1. 내 삶에서 중단된 영적 사역이나 결심이 있다면 무엇 때문에 멈추었나요?\n2. 하나님의 돌보심을 경험했던 순간을 기억하며 감사를 고백해 보세요.\n3. "천지의 하나님의 종"이라는 정체성이 나의 일상에서 어떻게 나타나야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-17', E'성전 재건의 기쁨 (에스라 6장)', E'에스라 6장', E'다리오 왕이 보물전각에서 고레스 왕의 조서를 발견하는 순간, 하나님께서는 역사의 물줄기를 다시 돌려놓으셨습니다. 메대의 악메다 궁성에서 찾아낸 두루마리에는 예루살렘 성전 재건에 대한 구체적인 명령이 기록되어 있었습니다. 높이와 너비가 육십 규빗이며, 큰 돌 세 켜에 새 나무 한 켜를 놓고, 모든 경비는 왕실에서 부담한다는 내용이었습니다. 더욱이 느부갓네살이 탈취했던 성전 기물들을 돌려보내라는 명령까지 포함되어 있었습니다.\n\n다리오 왕의 새로운 조서는 단순히 성전 재건을 허락하는 것을 넘어섰습니다. 유브라데 강 건너편 총독들에게 공사를 방해하지 말 것을 명하고, 오히려 왕의 재산에서 경비를 끊임없이 지원하도록 했습니다. 제사에 필요한 수송아지와 양, 밀과 소금, 포도주와 기름까지 날마다 공급하라는 구체적인 지시가 내려졌습니다. 이전에는 방해꾼이었던 자들이 이제는 성전 건축을 돕는 조력자가 되었습니다.\n\n학개와 스가랴 선지자의 격려 가운데 유다 장로들이 공사를 진행하자 모든 일이 형통했습니다. 다리오 왕 제육년 아달월 삼일, 마침내 성전이 완공되었습니다. 이스라엘 백성은 수소 백 마리와 숫양 이백 마리, 어린 양 사백 마리를 드리며 기쁨으로 봉헌식을 거행했습니다. 제사장과 레위인들은 모세의 책에 기록된 대로 각자의 직무를 수행하기 시작했습니다.\n\n성전 완공 후 첫 유월절은 특별한 의미를 지녔습니다. "사로잡혔다가 돌아온 이스라엘 자손과 자기 땅에 사는 이방 사람의 더러운 것으로부터 스스로를 구별한 모든 이스라엘 사람들"(스 6:21)이 함께 유월절 양을 먹었습니다. 칠십 년의 포로 생활 후 처음으로 성전에서 드리는 유월절이었습니다. 이레 동안 무교절을 지키며 온 백성이 즐거워했습니다. 하나님께서 앗수르 왕의 마음까지 돌려 성전 건축을 돕게 하신 은혜를 깊이 체험한 것입니다.', E'오늘의 핵심\n하나님께서는 페르시아 제국의 행정 체계까지 사용하셔서 중단되었던 성전 재건을 완성하게 하시고, 회복된 예배를 통해 백성에게 참된 기쁨을 허락하셨습니다.\n\n묵상 질문\n1. 하나님께서 이방 왕의 마음을 돌이키셔서 당신의 뜻을 이루신 경험이 있으신가요?\n2. 오랜 기다림 끝에 이루어진 하나님의 약속을 경험하며 어떤 감사를 드렸나요?\n3. 회복된 예배가 내 삶에 가져다준 기쁨과 변화는 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-18', E'에스라의 결심 (에스라 7장)', E'에스라 7장', E'바벨론 포로에서 1차 귀환이 있은 지 약 80년이 지났습니다. 아닥사스다 왕이 페르시아를 다스리던 때, 하나님께서는 특별한 인물을 예비하고 계셨습니다. 에스라는 대제사장 아론의 16대 손으로서 그 혈통의 정통성을 분명히 하고 있으며, "이스라엘의 하나님 여호와께서 주신 모세의 율법에 익숙한 학자"(스 7:6)로 소개됩니다. 그는 단순히 율법을 아는 것에 그치지 않고, 그것을 연구하여 준행하며 이스라엘에게 가르치기로 결심한 사람이었습니다.\n\n놀라운 것은 이방 왕 아닥사스다가 에스라에게 전폭적인 지원을 아끼지 않았다는 점입니다. 왕은 에스라를 "하늘의 하나님의 율법에 완전한 학자 겸 제사장"으로 인정하며, 예루살렘으로 돌아가고자 하는 모든 이스라엘 백성이 그와 함께 갈 수 있도록 허락합니다. 더 나아가 성전 예배를 위한 막대한 재정 지원과 함께 성전 봉사자들에 대한 세금 면제까지 명령합니다. 이는 단순한 왕의 호의가 아니라 하나님의 주권적인 역사하심이었습니다.\n\n에스라는 바벨론에서 안정되고 영향력 있는 지위를 누리고 있었습니다. 그러나 그는 편안한 삶을 포기하고 험난한 귀환길을 선택합니다. 첫째 달 초하루에 바벨론을 떠나 넉 달이 걸려 다섯째 달 초하루에 예루살렘에 도착한 이 여정은 "하나님의 선한 손의 도우심"으로 가능했습니다. 에스라의 귀환은 성전 재건이라는 외적 과업을 넘어, 하나님의 말씀으로 백성의 영적 갱신을 이루려는 거룩한 사명에서 비롯된 것이었습니다.', E'오늘의 핵심\n하나님께서는 율법에 정통하고 그것을 삶으로 실천하며 가르치기로 결심한 에스라를 통해 포로 귀환 공동체의 영적 개혁을 준비하십니다.\n\n묵상 질문\n1. 에스라처럼 하나님의 말씀을 연구하고 준행하며 가르치는 삶을 살고 있나요?\n2. 편안함과 안정을 포기하고서라도 하나님의 부르심에 순종할 준비가 되어 있나요?\n3. 하나님의 선한 손이 나와 함께하심을 경험하며 살아가고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-19', E'에스라의 결심 (에스라 8장)', E'에스라 8장', E'에스라가 이끄는 2차 포로 귀환은 1차 귀환과는 다른 성격을 지니고 있었습니다. 스룹바벨의 귀환이 성전 재건이라는 물리적 과제를 중심으로 했다면, 에스라의 귀환은 영적 개혁과 율법 교육이라는 내면적 회복을 목표로 삼았습니다. 에스라 8장은 이 귀환 여정의 구체적인 모습을 보여줍니다.\n\n먼저 기록된 것은 귀환자들의 명단입니다. 비느하스, 이다말, 다윗의 후손을 비롯해 열두 가문에서 약 1,500명의 남자들이 에스라와 함께했습니다. 이들은 단순한 이주민이 아니라, 이후 유대 공동체의 영적 재건을 이끌어갈 핵심 인물들이었습니다. 특히 에스라는 아하와 강가에서 레위인이 한 명도 없음을 발견하고, 가시뱌로 사람을 보내어 성전 봉사자들을 데려옵니다. 이는 그가 단순히 귀환만을 목적으로 하지 않고, 예루살렘에서 온전한 예배 공동체를 세우고자 했음을 보여줍니다.\n\n귀환 여정 전, 에스라는 아하와 강가에서 금식을 선포합니다. "우리가 전에 왕에게 아뢰기를 우리 하나님의 손은 자기를 찾는 모든 자에게 선을 베푸시고"(스 8:22)라고 했던 고백 때문에, 그는 왕에게 호위병을 요청하는 대신 오직 하나님의 보호하심만을 의지하기로 결단합니다. 이 금식과 기도는 그들의 여정이 단순한 이주가 아닌 믿음의 순례임을 분명히 보여줍니다.\n\n왕과 백성들이 성전을 위해 바친 막대한 헌물들을 제사장들에게 맡기며, 에스라는 그들이 "여호와께 거룩한 자"임을 상기시킵니다. 넉 달의 긴 여정 끝에 예루살렘에 도착한 그들은 즉시 번제를 드립니다. 이스라엘 전체를 위한 수송아지 열두 마리는 열두 지파의 연합을 상징하며, 포로기를 거치며 흩어졌던 하나님의 백성이 다시 하나 되었음을 선포하는 것이었습니다.', E'오늘의 핵심\n에스라는 귀환 여정을 철저히 기도와 금식으로 준비하며, 오직 하나님의 보호하심만을 의지하여 예루살렘으로 향합니다. 그의 귀환은 단순한 이주가 아닌 영적 회복을 위한 거룩한 부르심이었습니다.\n\n묵상 질문\n1. 에스라가 왕의 호위 대신 하나님의 보호를 택한 것처럼, 나는 어떤 상황에서 하나님만을 의지하는 선택을 하고 있나요?\n2. 귀환자 명단에 이름이 기록된 것처럼, 하나님 나라를 위해 나의 이름이 기억되려면 어떻게 살아야 할까요?\n3. 에스라가 레위인들을 찾아 데려온 것처럼, 공동체의 영적 필요를 채우기 위해 내가 할 수 있는 일은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-20', E'개혁을 위하여', E'에스라 10장', E'에스라가 하나님의 성전 앞에 엎드려 울며 죄를 자복할 때, 놀라운 일이 벌어집니다. 한 사람의 진심 어린 회개가 온 백성의 통곡으로 번진 것입니다. 에스라는 이스라엘이 이방 여인을 아내로 맞이하여 하나님의 명령을 거역하는 현실 앞에서, 남의 죄를 지적하기 전에 먼저 자기 민족의 죄를 자신의 죄로 끌어안고 하나님 앞에 엎드렸습니다. 오랜 포로 생활에서 돌아와 성전까지 재건했음에도 여전히 하나님의 뜻을 떠나 살고 있는 모습이, 그에게는 도저히 외면할 수 없는 아픔이었습니다.\n\n그 진실한 회개 앞에서 백성 가운데 스가냐가 먼저 나서서 말합니다. "이스라엘에게 아직도 소망이 있습니다." 이 고백이 참으로 은혜롭습니다. 죄의 현실을 직시하면서도 절망에 머무르지 않고, 하나님께 돌아가면 여전히 길이 있다고 선언하는 것입니다. 그리고 백성은 실제로 행동에 옮깁니다. 삼 개월에 걸쳐 이방 아내를 떠나보내는 일을 조사하고 정리합니다. 쉬운 결단이 아니었을 것입니다. 이미 자녀를 낳은 가정도 있었습니다. 그럼에도 하나님의 말씀 앞에서 자신의 삶을 바로잡기로 선택한 것입니다.\n\n우리의 일상에도 이미 익숙해져서 돌아볼 생각조차 하지 못하는 영역이 있을 수 있습니다. 직장에서, 관계에서, 습관 속에서 어느새 하나님의 뜻과 멀어진 부분이 없는지 돌아볼 필요가 있습니다. 진정한 개혁은 남을 바꾸는 데서 시작되지 않습니다. 에스라처럼 먼저 자신을 하나님 앞에 내려놓는 데서 시작됩니다. 그리고 스가냐의 고백처럼, 우리에게도 아직 소망이 있습니다. 오늘, 하나님 앞에 내려놓아야 할 것이 무엇인지 조용히 여쭈어 보시기 바랍니다.', E'오늘의 핵심\n민족의 죄를 자신의 것으로 받아들여 회개하는 에스라의 기도를 시작으로 하나님의 언약과 율법에 기반한 개혁의 주춧돌이 놓입니다.\n\n묵상 질문\n1. 하나님은 백성의 죄를 보시고도 왜 자꾸 기회를 주시나요?\n2. 내가 다른 사람의 잘못을 볼 때 에스라처럼 함께 회개할 수 있나요?\n3. 이 시대 내 신앙공동체가 회복되기 위해 내가 먼저 할 것이 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-21', E'하나님의 기쁨과 이웃의 기쁨 (느헤미야 1장)', E'느헤미야 1장', E'기원전 445년경, 페르시아 왕 아닥사스다 제20년의 일입니다. 왕의 술 관원으로 수산 궁에서 일하던 느헤미야에게 예루살렘의 소식이 전해집니다. 바벨론 포로에서 돌아온 동족들이 큰 환난과 능욕을 당하고 있으며, 예루살렘 성은 허물어지고 성문들은 불에 탄 채로 방치되어 있다는 것이었습니다. 이미 90여 년 전 첫 번째 귀환이 있었고, 성전도 재건되었지만, 성벽 없는 도시는 여전히 무방비 상태였습니다.\n\n이 소식을 들은 느헤미야의 반응은 즉각적이고도 깊이 있었습니다. 그는 앉아서 울고, 수일 동안 슬퍼하며, 금식하며 기도했습니다. 페르시아 왕궁의 안락한 자리에 있으면서도 동족의 고통을 자신의 고통으로 받아들인 것입니다. 그의 기도는 먼저 하나님의 위대하심과 신실하심을 인정하는 것으로 시작됩니다. "크고 두려우신 하나님이여 주를 사랑하고 주의 계명을 지키는 자에게 언약을 지키시며 긍휼을 베푸시는 주여"(느 1:5). \n\n이어서 느헤미야는 이스라엘의 죄를 자복합니다. 단순히 남의 죄가 아니라 "나와 내 아버지의 집이 범죄하여"라고 고백하며, 자신도 그 죄의 공동체 일원임을 인정합니다. 그리고 모세를 통해 주신 하나님의 약속, 곧 흩어진 백성을 다시 모으시겠다는 언약의 말씀을 붙듭니다. 느헤미야의 기도는 단순한 탄식이 아니라 하나님의 약속에 근거한 믿음의 기도였습니다.\n\n왕의 술 관원이라는 높은 지위에 있으면서도 동족의 아픔에 함께 울고, 그들의 회복을 위해 자신이 무엇을 할 수 있을지 하나님께 묻는 느헤미야의 모습은 오늘 우리에게도 도전을 줍니다. 진정한 리더십은 높은 자리에서 내려다보는 것이 아니라, 백성의 아픔을 품고 하나님 앞에 무릎 꿇는 데서 시작됩니다.', E'오늘의 핵심\n느헤미야는 왕궁의 안락함 속에서도 동족의 고통을 자신의 것으로 받아들이고, 눈물과 금식 기도로 하나님께 나아갔습니다.\n\n묵상 질문\n1. 내 주변의 어떤 소식이 나를 앉아서 울게 하고 기도하게 만드나요?\n2. 하나님의 약속을 붙들고 기도할 때, 나는 어떤 말씀을 의지하고 있나요?\n3. 높은 자리나 안정된 위치에 있을 때도 공동체의 아픔에 민감할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-22', E'하나님의 기쁨과 이웃의 기쁨 (느헤미야 2장)', E'느헤미야 2장', E'느헤미야가 왕의 술 관원으로서 왕 앞에 나아갔을 때, 그의 얼굴에는 감출 수 없는 수심이 가득했습니다. 아닥사스다 왕이 "네가 병이 없거늘 어찌하여 얼굴에 수심이 있느냐"고 묻자, 느헤미야는 크게 두려워했다고 성경은 전합니다. 페르시아 왕 앞에서 개인적인 감정을 드러낸다는 것은 목숨을 걸어야 하는 일이었기 때문입니다. 그러나 느헤미야는 조상들의 묘실이 있는 예루살렘의 황폐함을 더 이상 마음에만 담아둘 수 없었습니다.\n\n왕이 "그러면 네가 무엇을 원하느냐"고 물었을 때, 느헤미야가 보인 반응은 우리에게 중요한 교훈을 줍니다. 그는 곧바로 하늘의 하나님께 묵도했습니다. 순간의 기도였지만, 이는 그가 평소 얼마나 기도의 사람이었는지를 보여줍니다. 그리고 담대하게 예루살렘으로 보내달라고 요청했고, 필요한 조서와 재목까지 구체적으로 요구했습니다. 하나님의 선한 손이 그를 도우셨기에 왕은 이 모든 것을 허락했습니다.\n\n예루살렘에 도착한 느헤미야는 사흘 동안 침묵했습니다. 그리고 밤중에 몇몇 사람과 함께 무너진 성벽을 둘러보았습니다. 이는 단순한 시찰이 아니라 기도하며 하나님의 뜻을 구하는 시간이었습니다. 충분히 준비된 후에야 비로소 그는 백성들에게 비전을 나누었습니다. "예루살렘 성을 건축하여 다시 수치를 당하지 말자"는 그의 외침에 백성들은 "일어나 건축하자"고 화답했습니다.\n\n산발랏과 도비야 같은 대적들이 조롱하고 방해했지만, 느헤미야의 대답은 분명했습니다. "하늘의 하나님이 우리를 형통하게 하시리니." 이것이 그의 확신이었고 힘의 근원이었습니다. 느헤미야는 왕의 권세나 자신의 능력이 아닌, 오직 하나님의 손길을 의지했습니다. 무너진 성벽 앞에서도, 대적들의 조롱 앞에서도 흔들리지 않을 수 있었던 것은 바로 이 믿음 때문이었습니다.', E'오늘의 핵심\n느헤미야는 위기의 순간에도 먼저 기도했고, 하나님의 선한 손이 함께하심을 확신하며 담대하게 사명의 길을 걸어갔습니다.\n\n묵상 질문\n1. 중요한 결정의 순간에 나는 먼저 하나님께 묵도하고 있나요?\n2. 하나님의 일을 위해 구체적으로 계획하고 준비하는 지혜를 구하고 있나요?\n3. 대적들의 조롱과 방해 앞에서도 "하나님이 형통케 하신다"는 확신을 가지고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-24', E'하나님의 기쁨과 이웃의 기쁨 (느헤미야 3장)', E'느헤미야 3장', E'예루살렘 성벽 재건의 구체적인 모습이 느헤미야 3장을 통해 생생하게 전해집니다. 대제사장 엘리아십부터 시작하여 금장색과 상인들에 이르기까지, 각계각층의 사람들이 자발적으로 참여한 이 거대한 프로젝트는 단순한 건축 공사 이상의 의미를 담고 있습니다.\n\n느헤미야는 이 장에서 42개 그룹의 이름을 하나하나 기록하며, 각자가 맡은 구역과 수행한 역할을 세세히 보존합니다. 양문에서 시작하여 시계 반대 방향으로 성벽을 따라가며 기록된 이 명단은, 하나님의 일에 참여한 모든 이들의 헌신을 귀하게 여기시는 하나님의 마음을 보여줍니다. 특별히 "자기 집과 마주 대한 곳"을 중수했다는 표현이 반복되는데, 이는 각자가 가장 잘 알고 애착을 가진 구역을 책임졌음을 의미합니다.\n\n주목할 만한 것은 이 일에 참여한 사람들의 다양성입니다. 종교 지도자인 제사장들, 정치 지도자들, 금장색과 향품 장사 같은 전문 기술자들, 그리고 평범한 주민들까지 모두가 한마음으로 성벽 재건에 동참했습니다. 심지어 살룸의 딸들도 아버지와 함께 성벽을 중수했다는 기록은, 남녀노소를 불문하고 모든 이가 하나님의 일에 쓰임 받을 수 있음을 보여줍니다.\n\n그러나 드고아 귀족들이 "그들의 주인들의 공사를 분담하지 아니하였으며"(5절)라는 기록도 있습니다. 같은 드고아 사람들이 두 구역을 중수한 것과 대조되는 이 모습은, 하나님의 일 앞에서 교만과 특권 의식이 얼마나 무익한지를 드러냅니다.\n\n이 성벽 재건 프로젝트는 단순히 물리적 방어벽을 쌓는 것이 아니라, 흩어졌던 하나님의 백성이 하나의 공동체로 결속되는 과정이었습니다. 각자의 재능과 위치에서 최선을 다할 때, 52일이라는 놀라운 기간 안에 불가능해 보였던 일이 완성될 수 있었던 것입니다.', E'오늘의 핵심\n예루살렘 성벽 재건은 각계각층의 사람들이 자발적으로 참여하여 하나의 공동체로 결속되는 과정이었으며, 하나님께서는 각 사람의 헌신을 귀하게 여기셨습니다.\n\n묵상 질문\n1. 하나님의 일에 나의 재능과 위치를 어떻게 사용할 수 있을까요?\n2. 공동체를 세워가는 일에 내가 맡은 ''자기 집과 마주 대한 곳''은 어디일까요?\n3. 드고아 귀족들처럼 하나님의 일을 회피하게 만드는 나의 교만은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-25', E'성벽 재건을 위한 열심 (느헤미야 4장)', E'느헤미야 4장', E'성벽 재건이 시작되자 적대 세력의 반응은 즉각적이었습니다. 산발랏은 유다 사람들을 공개적으로 조롱했고, 도비야는 "여우가 올라가도 곧 무너지리라"며 비웃었습니다. 이들의 조롱은 단순한 말의 공격을 넘어, 아라비아와 암몬, 아스돗 사람들과 연합하여 무력 공격을 모의하는 실질적인 위협으로 발전했습니다. 예루살렘을 치고 혼란을 일으키려는 그들의 계획은 막 시작된 재건 사업을 뿌리째 흔들려는 시도였습니다.\n\n더욱 어려운 것은 내부의 상황이었습니다. "짐을 나르는 자의 힘이 다 빠졌으니 우리가 성을 건축하지 못하리라"는 유다 사람들의 탄식은 육체적 피로를 넘어 심리적 좌절감을 드러내고 있습니다. 흙 무더기는 여전히 많은데 일꾼들의 기력은 소진되었고, 원수들의 근처에 사는 동족들은 열 번이나 찾아와 "너희가 우리에게로 와야 하리라"며 공사를 포기하도록 압박했습니다.\n\n이러한 안팎의 위기 앞에서 느헤미야가 보여준 리더십은 주목할 만합니다. 그는 먼저 하나님께 기도했지만, 동시에 구체적인 방어 전략을 세웠습니다. 성벽 뒤 낮고 넓은 곳에 종족별로 무장한 백성을 배치했고, 일꾼의 절반은 건축을, 절반은 경비를 서도록 했습니다. 특별히 "너희는 그들을 두려워하지 말고 지극히 크시고 두려우신 주를 기억하고 너희 형제와 자녀와 아내와 집을 위하여 싸우라"는 그의 외침은 백성들에게 싸워야 할 이유와 의지할 분을 분명히 제시했습니다.\n\n"우리 하나님이 우리를 위하여 싸우시리라"는 느헤미야의 선포는 단순한 정신적 위안이 아니었습니다. 하나님께서 실제로 대적들의 계략을 무너뜨리셨고, 백성들은 한 손에 연장을, 한 손에 병기를 들고 건축을 계속할 수 있었습니다. 밤에는 파수하고 낮에는 일하며, 물을 길으러 갈 때조차 병기를 놓지 않는 그들의 모습은 하나님을 의지하되 최선의 노력을 다하는 믿음의 본을 보여줍니다.', E'오늘의 핵심\n외부의 조롱과 위협, 내부의 피로와 좌절 속에서도 느헤미야는 기도와 실천을 병행하며 하나님께서 싸우시는 전쟁임을 선포했습니다.\n\n묵상 질문\n1. 일상의 도전과 위협 앞에서 나는 어떻게 반응하고 있나요?\n2. 기도하면서도 최선을 다해 준비하고 행동하는 균형을 유지하고 있나요?\n3. "우리 하나님이 우리를 위하여 싸우시리라"는 확신이 내 삶에 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-26', E'성벽 재건을 위한 열심 (느헤미야 5장)', E'느헤미야 5장', E'성벽 재건이 한창 진행되던 중, 예상치 못한 곳에서 위기가 터져 나왔습니다. 외부의 적이 아닌 내부의 갈등이었습니다. 백성들이 그들의 형제인 유다 사람들을 향해 부르짖기 시작했습니다. 어떤 이들은 가족을 먹일 양식이 없어 탄식했고, 어떤 이들은 흉년에 곡식을 얻으려 밭과 포도원을 저당 잡혔으며, 또 어떤 이들은 왕에게 세금을 바치려 빚을 내야 했습니다. 가장 가슴 아픈 것은 자녀들을 종으로 파는 지경에 이른 것이었습니다. 성벽은 세워지고 있었지만, 공동체는 무너지고 있었던 것입니다.\n\n느헤미야는 이 소식에 크게 노했습니다. 그러나 즉각적으로 대응하지 않고 깊이 생각한 후에 행동했습니다. 이것이 지도자의 지혜입니다. 그는 귀족들과 민장들을 모아 대회를 열고 그들의 잘못을 지적했습니다. "우리는 이방인의 손에 팔린 우리 형제 유다 사람들을 우리의 힘을 다하여 도로 찾았거늘 너희는 너희 형제를 팔고자 하느냐"(느 5:8). 느헤미야의 꾸짖음은 단순한 경제 문제를 넘어 하나님의 백성으로서의 정체성을 일깨우는 것이었습니다.\n\n더욱 놀라운 것은 느헤미야 자신의 모범이었습니다. 그는 12년간 총독의 녹을 받지 않았고, 오히려 매일 150명이 넘는 사람들을 자신의 상에서 대접했습니다. 이전 총독들이 백성을 압제하며 은 사십 세겔과 양식과 포도주를 빼앗았던 것과는 정반대의 모습이었습니다. 그는 "하나님을 경외하므로" 그렇게 행했다고 고백합니다.\n\n느헤미야의 리더십은 백성들의 마음을 움직였습니다. 귀족들은 즉시 이자 받기를 중단하고 빼앗은 것들을 돌려주겠다고 약속했으며, 실제로 그 말한 대로 행했습니다. 성벽 재건은 계속되었고, 더 중요하게는 무너졌던 공동체가 회복되었습니다. 오늘날 우리 사회와 교회 공동체에도 느헤미야와 같은 리더십이 필요합니다. 자신의 유익을 내려놓고 공동체를 섬기며, 하나님을 경외함으로 행동하는 지도자 말입니다.', E'오늘의 핵심\n느헤미야는 내부의 경제적 갈등을 하나님을 경외하는 마음과 솔선수범의 리더십으로 해결하며, 무너진 공동체를 회복시킵니다.\n\n묵상 질문\n1. 나는 어려움에 처한 이웃의 부르짖음에 어떻게 반응하고 있나요?\n2. 분노할 때 즉각 반응하지 않고 깊이 생각한 후 행동하고 있나요?\n3. 내가 가진 권리나 특권을 공동체를 위해 내려놓을 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-27', E'성벽 재건을 위한 열심 (느헤미야 6장)', E'느헤미야 6장', E'성벽 재건이 거의 완성 단계에 이르자 대적들의 방해는 더욱 교묘해졌습니다. 산발랏과 도비야는 이제 물리적 공격 대신 심리전을 택했습니다. 오노 평지에서 만나자는 제안은 화해의 제스처처럼 보였지만, 느헤미야는 그들의 진짜 의도를 꿰뚫어 보았습니다. "내가 이제 큰 역사를 하니 내려가지 못하겠노라"(느 6:3)는 그의 대답은 우선순위를 분명히 아는 사람의 지혜로운 거절이었습니다.\n\n네 번의 거절에도 포기하지 않은 산발랏은 다섯 번째에는 봉하지 않은 편지를 보냈습니다. 봉하지 않은 편지란 누구나 읽을 수 있도록 공개된 것으로, 느헤미야가 왕이 되려 한다는 거짓 소문을 퍼뜨리려는 의도였습니다. 페르시아 제국에서 반역 혐의는 곧 사형을 의미했기에, 이는 생명을 위협하는 모략이었습니다. 그러나 느헤미야는 동요하지 않았습니다. 오히려 "이제 내 손을 힘있게 하옵소서"라고 기도하며 하나님께 더욱 의지했습니다.\n\n더 충격적인 것은 내부의 배신이었습니다. 선지자로 자처하는 스마야가 성전 안으로 피신하라고 권했지만, 이는 율법을 어기게 하려는 함정이었습니다. 제사장이 아닌 사람이 성소에 들어가는 것은 율법 위반이었기 때문입니다. 느헤미야는 "나 같은 자가 어찌 도망하며"라고 당당히 거절했습니다. 하나님의 일을 하는 사람이 하나님의 법을 어기며 목숨을 구하는 것은 모순임을 알았던 것입니다.\n\n52일 만에 성벽이 완성되었을 때, 대적들은 크게 낙담했습니다. 그들이 두려워한 이유는 성벽의 견고함 때문이 아니라, "우리 하나님께서 이 역사를 이루신 것을" 깨달았기 때문입니다. 인간의 모든 방해와 음모를 뚫고 하나님의 뜻이 성취되는 것을 목격한 것입니다. 느헤미야가 보여준 분별력과 담대함은 하나님께 대한 확고한 신뢰에서 나왔고, 그 신뢰가 불가능해 보였던 일을 가능케 했습니다.', E'오늘의 핵심\n느헤미야는 대적들의 교묘한 음모와 내부의 배신 앞에서도 하나님께 대한 신뢰를 잃지 않았고, 분별력 있는 결단으로 마침내 52일 만에 성벽 재건을 완성했습니다.\n\n묵상 질문\n1. 좋은 제안처럼 보이는 유혹 앞에서 하나님의 일을 우선순위로 지키고 있나요?\n2. 두려움에 굴복하지 않고 "내 손을 힘있게 하옵소서"라고 기도할 때는 언제인가요?\n3. 하나님께서 이루신 일임을 주변 사람들이 인정할 만한 열매가 내 삶에 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-28', E'성벽 재건을 위한 열심 (느헤미야 7장)', E'느헤미야 7장', E'52일 만에 예루살렘 성벽이 완성되었습니다. 무너진 성벽을 다시 세우는 것은 단순히 돌을 쌓는 일이 아니었습니다. 그것은 하나님의 백성으로서의 정체성을 회복하고, 언약 공동체를 재건하는 거룩한 사역이었습니다. 느헤미야는 성벽 재건이라는 외적 과업을 마친 후, 이제 더 중요한 내적 재건에 착수합니다. 바로 백성들의 계보를 정리하고, 각자의 자리와 역할을 분명히 하는 일이었습니다.\n\n느헤미야가 가장 먼저 한 일은 신실한 지도자들을 세우는 것이었습니다. 그는 자신의 동생 하나니와 "충성스러운 사람이요 하나님을 경외함이 무리 중에서 뛰어난"(느 7:2) 하나냐를 예루살렘의 관원으로 임명합니다. 성벽은 완성되었지만 아직 경계를 늦출 수 없었기에, 문을 여닫는 시간과 파수의 방법까지 세심하게 지시합니다. 특별히 각 사람이 자기 집 맞은편을 지키게 한 것은, 공동체의 안전이 곧 자신의 안전임을 깨닫게 하는 지혜로운 배치였습니다.\n\n이어지는 긴 명단은 단순한 인구 조사가 아니었습니다. 바벨론 포로에서 귀환한 백성들의 계보를 확인하는 것은 언약 백성으로서의 정체성을 확인하는 작업이었습니다. 특히 제사장들 중 일부가 자신의 계보를 증명하지 못해 직무에서 배제된 것은, 하나님께 드리는 예배의 순결성을 지키려는 엄격한 조치였습니다. 이 명단 속에는 각 가문의 역사와 하나님의 신실하심이 담겨 있었습니다. 포로기를 거치면서도 자신들의 정체성을 잃지 않고 돌아온 4만 2360명의 백성들, 그들 하나하나가 하나님의 언약이 여전히 유효함을 증명하는 살아있는 증거였습니다.\n\n오늘날 우리도 때로는 자신의 영적 계보와 정체성을 점검해야 할 때가 있습니다. 내가 누구의 자녀이며, 어떤 믿음의 유산을 이어받았는지, 그리고 어떤 사명을 감당해야 하는지를 분명히 아는 것은 신앙생활의 기초입니다. 느헤미야가 보여준 것처럼, 외적인 성공 이후에도 내적인 정비를 게을리하지 않는 지혜가 필요합니다.', E'오늘의 핵심\n성벽 재건을 완성한 느헤미야는 신실한 지도자들을 세우고 귀환한 백성들의 계보를 정리하며, 언약 공동체의 정체성을 확립하는 내적 재건에 착수합니다.\n\n묵상 질문\n1. 하나님을 경외하는 리더를 세우는 일이 왜 중요할까요?\n2. 나의 영적 정체성과 계보를 분명히 알고 있나요?\n3. 외적 성취 후에도 내적 점검을 게을리하지 않으려면 어떻게 해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-29', E'초막절을 기념한 신앙사경회 (느헤미야 8장)', E'느헤미야 8장', E'예루살렘 성벽 재건이라는 대역사를 마친 이스라엘 백성들에게 이제 더 중요한 과제가 남아 있었습니다. 무너진 성벽을 다시 세우는 것보다 더 시급한 것은 무너진 신앙을 다시 세우는 일이었습니다. 일곱째 달이 되자 백성들이 자발적으로 수문 앞 광장에 모여 학사 에스라에게 모세의 율법책을 가져오기를 청합니다. 이는 하나님의 말씀을 향한 백성들의 갈급함을 보여주는 놀라운 장면입니다.\n\n새벽부터 정오까지 이어진 말씀 낭독의 현장은 참으로 감동적입니다. 에스라가 특별히 지은 나무 강단에 서서 율법책을 펼 때 모든 백성이 일어섰고, 하나님을 송축할 때는 손을 들고 "아멘, 아멘"으로 화답하며 얼굴을 땅에 대고 경배했습니다. 이 날의 예배는 단순한 낭독이 아니었습니다. 레위인들이 백성들 사이에서 율법을 해석하고 가르쳐 모두가 그 뜻을 깨달을 수 있도록 했습니다.\n\n말씀을 들은 백성들의 반응은 눈물이었습니다. 오랜 포로 생활과 귀환 후의 어려움 속에서 잊고 있었던 하나님의 뜻을 깨달았기 때문입니다. 그러나 느헤미야와 에스라는 이날이 거룩한 날임을 선포하며 슬퍼하지 말고 기뻐하라고 권면합니다. "여호와로 인하여 기뻐하는 것이 너희의 힘이니라"(느 8:10)는 선언은 회개의 눈물을 기쁨의 눈물로 바꾸어 놓았습니다.\n\n이어서 백성들은 율법에 기록된 초막절을 지킵니다. 여호수아 시대 이후로 지켜지지 않았던 이 절기를 온 백성이 함께 지키며 크게 기뻐했습니다. 성벽 재건이 외적 회복이었다면, 말씀을 통한 이 영적 각성은 이스라엘의 진정한 회복의 시작이었습니다. 하나님의 백성다운 정체성을 되찾은 이들은 이제 말씀대로 살아가는 새로운 삶을 시작하게 됩니다.', E'오늘의 핵심\n성벽 재건을 마친 이스라엘 백성들이 스스로 모여 하나님의 말씀을 듣고자 했고, 말씀을 깨달은 백성들은 회개의 눈물을 흘렸다가 여호와로 인한 기쁨을 회복했습니다.\n\n묵상 질문\n1. 백성들이 자발적으로 모여 말씀을 청한 것처럼, 나는 하나님의 말씀을 향한 갈급함을 가지고 있나요?\n2. 말씀을 들을 때 회개의 눈물과 기쁨을 동시에 경험한 적이 있나요?\n3. "여호와로 인하여 기뻐하는 것이 너희의 힘"이라는 말씀이 오늘 나에게 주는 의미는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-05-31', E'초막절을 기념한 신앙사경회 (느헤미야 9장)', E'느헤미야 9장', E'예루살렘 성벽이 완공된 후, 이스라엘 백성은 스물나흗 날에 다시 모여 금식하며 굵은 베옷을 입고 참회의 자리에 나아갑니다. 에스라의 율법 낭독을 통해 하나님의 뜻을 깨달은 백성들은 이제 그들의 죄와 조상들의 허물을 자복하며 진정한 회개의 시간을 갖습니다. 낮 사분의 일은 하나님의 율법책을 듣고, 또 사분의 일은 죄를 자복하며 여호와께 경배하는 모습은 말씀과 기도가 균형을 이룬 참된 영적 각성의 모습을 보여줍니다.\n\n레위인들이 인도하는 이 회개 기도는 이스라엘 역사 전체를 아우르는 장대한 고백입니다. 천지 창조부터 시작하여 아브라함의 부르심, 출애굽의 구원, 광야에서의 인도하심, 그리고 가나안 정착에 이르기까지 하나님의 신실하신 은혜를 회상합니다. 특히 이 기도에서 반복되는 주제는 하나님의 변함없는 사랑과 이스라엘의 거듭된 배반입니다. "그들과 우리 조상들이 교만하고 목을 굳게 하여 주의 명령을 듣지 아니하고"(16절)라는 고백은 단순히 과거의 잘못을 인정하는 것을 넘어, 현재 그들 자신의 모습까지 포함하는 통렬한 자기반성입니다.\n\n이 기도에서 드러나는 하나님의 성품은 공의로우시면서도 긍휼이 풍성하신 분이라는 것입니다. 백성들이 금송아지를 만들어 하나님을 모독했을 때도, 선지자들을 죽이고 율법을 거역했을 때도, 하나님은 그들을 완전히 버리지 않으셨습니다. 오히려 "주의 크신 긍휼로" 구원자들을 보내시고, "여러 번" 건져내시며, 끊임없이 돌아오도록 경계하셨습니다. 이스라엘의 역사는 곧 하나님의 인내와 사랑의 역사였음을 고백하는 것입니다.\n\n포로에서 돌아온 백성들이 이렇게 긴 역사적 회고를 통해 회개하는 이유는 분명합니다. 그들은 조상들의 실패가 자신들에게도 반복될 수 있음을 깨달았기 때문입니다. 성벽 재건이라는 외적 회복만으로는 충분하지 않습니다. 하나님과의 관계가 바로 서지 않으면, 견고한 성벽도 무너질 수밖에 없음을 역사가 증명했습니다. 그래서 그들은 지금 조상들의 죄와 자신들의 죄를 함께 고백하며, 새로운 출발을 다짐하고 있는 것입니다.', E'오늘의 핵심\n포로 귀환 공동체는 이스라엘 역사 전체를 돌아보며 하나님의 신실하심과 자신들의 거역을 고백하고, 조상들의 실패를 반복하지 않기 위해 철저한 회개의 자리로 나아갑니다.\n\n묵상 질문\n1. 내 삶의 역사 속에서 발견되는 하나님의 인내하심과 나의 거역은 무엇인가요?\n2. 참된 회개는 어떻게 과거의 실패를 현재의 변화로 이어지게 할까요?\n3. 하나님의 공의와 긍휼 사이에서 나는 어떤 은혜를 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-01', E'초막절을 기념한 신앙사경회 (느헤미야 10장)', E'느헤미야 10장', E'포로 귀환 공동체가 하나님의 율법 앞에서 눈물로 회개한 후, 그들의 신앙은 구체적인 결단과 실천으로 이어집니다. 느헤미야 10장은 언약 갱신 문서에 인봉하는 지도자들의 명단으로 시작됩니다. 총독 느헤미야를 필두로 제사장들, 레위인들, 그리고 백성의 지도자들이 차례로 이름을 올립니다. 이 명단은 단순한 서명자 목록이 아니라, 하나님 앞에서 새로운 삶을 살겠다는 공동체 전체의 엄숙한 서약을 보여줍니다.\n\n언약의 내용은 매우 구체적이고 실제적입니다. 첫째로 이방인과의 통혼 금지를 명시합니다. 이는 단순한 민족적 순수성 보존이 아니라 신앙의 순전함을 지키려는 의지의 표현입니다. 둘째로 안식일과 안식년 준수를 약속합니다. 안식일에는 매매를 하지 않고, 일곱째 해에는 땅을 쉬게 하며 모든 빚을 탕감하겠다는 것입니다. 이는 하나님께서 창조 질서 속에 심어두신 안식의 리듬을 회복하겠다는 결단입니다.\n\n셋째로 성전 유지를 위한 재정적 책임을 자발적으로 받아들입니다. 매년 성전세를 바치고, 제비를 뽑아 정기적으로 제단에 사를 나무를 공급하며, 각종 첫 열매와 십일조를 충실히 드리기로 합니다. "우리가 우리 하나님의 전을 버려 두지 아니하리라"(느 10:39)는 마지막 선언은 과거 성전을 소홀히 여겼던 실패를 반복하지 않겠다는 강한 의지를 담고 있습니다.\n\n이 언약 갱신은 율법의 무거운 짐을 다시 지는 것이 아니라, 하나님의 은혜에 감사하며 자발적으로 선택한 헌신입니다. 그들은 율법 준수를 통해 하나님과의 관계를 회복하고, 거룩한 공동체로 세워지기를 소망했습니다. 진정한 신앙 개혁은 감정적 회개에 그치지 않고 삶의 구체적인 변화로 나타나야 함을 이 본문은 가르쳐 줍니다.', E'오늘의 핵심\n포로 귀환 공동체는 율법 낭독과 회개 이후, 구체적인 언약 조항들을 정하고 지도자들부터 솔선수범하여 인봉함으로써 하나님께 대한 헌신을 새롭게 다집니다.\n\n묵상 질문\n1. 나의 신앙생활에서 구체적으로 개선하고 싶은 영역은 무엇인가요?\n2. 하나님의 전을 버려두지 않겠다는 결단이 오늘날 우리에게는 어떤 의미일까요?\n3. 신앙 공동체의 일원으로서 내가 감당해야 할 책임은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-02', E'유다 민족의 위기 (에스더 1장)', E'에스더 1장', E'페르시아 제국의 화려한 수산 궁전에서 벌어진 일은 한 나라의 흥망성쇠가 얼마나 인간의 교만과 연약함에 달려 있는지를 보여줍니다. 아하수에로 왕은 즉위 3년째에 무려 180일 동안 잔치를 베풀며 자신의 부와 권력을 과시합니다. 이어서 수산성 백성들을 위해 7일간 더 잔치를 열었는데, 그 호사스러움은 대리석 기둥과 금은 장식, 각기 다른 모양의 금잔에서 드러납니다. 이러한 과시욕은 단순히 부를 자랑하는 데 그치지 않고, 왕후 와스디까지도 전시의 대상으로 삼으려 합니다.\n\n제7일째 되던 날, 술에 취한 왕은 일곱 내시를 보내 왕후 와스디에게 왕관을 쓰고 나와 그녀의 아름다움을 뭇 백성과 관리들 앞에 보이라고 명합니다. 그러나 와스디는 이 명령을 거부합니다. 성경은 그녀가 거부한 이유를 밝히지 않지만, 왕의 요구가 왕후의 품위를 손상시키는 부당한 것이었음을 짐작할 수 있습니다. 와스디의 거부에 격분한 왕은 현자들과 의논한 끝에 그녀를 폐위시키고, 다시는 왕 앞에 나오지 못하게 하는 조서를 내립니다.\n\n이 사건의 본질은 단순한 부부 갈등이 아니라 권력의 오용과 인간 존엄성의 문제입니다. 왕의 측근 므무간은 왕후의 행동이 모든 여인들에게 영향을 미쳐 남편을 멸시하게 될 것이라며, 왕후를 폐위시키고 모든 남편이 집안의 주관자가 되어야 한다는 조서를 반포하도록 건의합니다. 한 사람의 상한 자존심이 제국 전체의 가정 질서를 뒤흔드는 법령으로 이어진 것입니다.\n\n에스더서 1장은 겉으로는 하나님의 이름이 전혀 등장하지 않지만, 인간의 교만과 권력 남용이 어떤 결과를 가져오는지를 보여주며, 동시에 하나님께서 이런 인간의 어리석음조차도 당신의 구원 계획 안에서 사용하실 것을 암시합니다. 와스디의 폐위는 결국 에스더가 왕후가 되는 길을 열었고, 이는 후에 유다 민족을 구원하는 결정적인 계기가 됩니다. 우리의 삶에서도 부당해 보이는 상황과 권력의 횡포를 만날 때, 그 너머에서 일하시는 하나님의 섭리를 신뢰하는 믿음이 필요합니다.', E'오늘의 핵심\n인간의 교만과 권력 남용은 파괴적인 결과를 낳지만, 하나님은 그러한 인간의 어리석음마저도 당신의 구원 계획을 이루시는 도구로 사용하십니다.\n\n묵상 질문\n1. 내 삶에서 권력이나 지위를 남용하여 다른 사람의 존엄성을 해친 적은 없습니까?\n2. 부당한 요구 앞에서 와스디처럼 용기 있게 거부할 수 있는 신앙의 힘이 있습니까?\n3. 불의한 상황 속에서도 하나님의 섭리가 일하고 계심을 믿고 기다릴 수 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-03', E'유다 민족의 위기 (에스더 2장)', E'에스더 2장', E'와스디가 폐위된 후, 페르시아 제국의 왕궁은 새로운 왕후를 찾는 일로 분주해집니다. 왕의 신하들이 제안한 대로 제국 전역에서 아름다운 처녀들이 수산 궁으로 모여듭니다. 이 거대한 선발 과정 속에서 하나님은 조용히 그분의 계획을 진행하고 계셨습니다. 바벨론 포로로 끌려온 베냐민 지파 사람 모르드개가 양육하던 에스더도 왕궁으로 들어가게 됩니다.\n\n에스더는 부모를 잃은 고아였지만, 사촌 오빠인 모르드개의 보살핌 속에서 자랐습니다. 그녀가 왕궁으로 들어갈 때, 모르드개는 중요한 지시를 합니다. 자신의 민족과 종족을 밝히지 말라는 것이었습니다. 이는 단순한 신변 보호를 넘어, 하나님의 백성이 이방 땅에서 살아가는 지혜였습니다. 에스더는 이 말씀에 순종하며, 왕궁에서도 모르드개의 가르침을 변함없이 따릅니다.\n\n궁녀를 주관하는 헤개는 에스더를 특별히 좋게 보았고, 그녀에게 은혜를 베풉니다. 열두 달의 정결 기간을 거쳐 왕 앞에 나아간 에스더는 헤개가 정한 것 외에는 아무것도 더 구하지 않았습니다. 이러한 겸손함과 절제는 모든 사람에게 사랑받는 품성이 되었고, 마침내 아하수에로 왕의 마음도 사로잡게 됩니다. 왕은 에스더를 와스디 대신 왕후로 삼고 성대한 잔치를 베풉니다.\n\n한편 모르드개는 날마다 후궁 뜰 앞을 왕래하며 에스더의 안부를 살폈고, 대궐 문에서 왕을 섬기던 중 왕을 암살하려는 음모를 발견하여 에스더를 통해 왕에게 알립니다. 이 일로 인해 모르드개의 충성은 궁중 일기에 기록됩니다.\n\n에스더가 왕후가 되기까지의 과정은 결코 우연이 아니었습니다. 고아였던 한 소녀가 제국의 왕후가 되는 극적인 신분 상승 뒤에는 하나님의 섭리가 있었습니다. 모르드개의 신실한 양육, 에스더의 순종과 겸손, 그리고 때를 따라 역사하시는 하나님의 손길이 함께했습니다. 우리의 평범한 일상 속에서도 하나님은 당신의 백성을 통해 구원의 역사를 준비하고 계십니다.', E'오늘의 핵심\n하나님께서는 고아 에스더를 페르시아의 왕후로 세우시며, 장차 있을 민족 구원의 도구로 준비시키십니다. 에스더의 순종과 겸손은 하나님의 섭리 안에서 빛을 발합니다.\n\n묵상 질문\n1. 내 삶의 평범한 자리에서도 하나님의 특별한 계획이 있음을 믿고 있습니까?\n2. 에스더처럼 권위자의 지도에 순종하며 겸손히 행하고 있습니까?\n3. 모르드개처럼 맡은 자리에서 충성스럽게 섬기고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-04', E'유다 민족의 위기 (에스더 3장)', E'에스더 3장', E'아하수에로 왕 치하에서 아각 사람 하만이 최고위직에 오르며 페르시아 제국에 어두운 그림자가 드리워지기 시작합니다. 모든 신하가 왕의 명령대로 하만에게 절하는 가운데, 유다인 모르드개만이 무릎을 꿇지도 절하지도 않습니다. 이는 단순한 불복종이 아니라 하나님 외에는 그 누구에게도 경배하지 않겠다는 신앙적 결단이었습니다. 그러나 하만의 분노는 한 개인을 넘어 민족 전체를 향한 살의로 번집니다. "모르드개만 죽이는 것이 부족하다"고 여긴 하만은 페르시아 전역의 유다인을 몰살시킬 음모를 꾸밉니다.\n\n하만의 계략은 치밀했습니다. 그는 왕에게 유다인들이 왕의 법을 지키지 않는 위험한 민족이라고 거짓 고발하며, 은 일만 달란트라는 막대한 뇌물까지 제시합니다. 왕은 깊이 생각해보지도 않고 자신의 인장 반지를 하만에게 넘겨주며 "너의 소견에 좋을 대로 행하라"고 합니다. 이로써 아달월 십삼일, 단 하루 만에 남녀노소를 막론하고 모든 유다인을 학살하라는 끔찍한 조서가 페르시아 전역에 반포됩니다.\n\n본문은 권력의 오만과 증오가 어떻게 무고한 생명들을 위협하는지 생생하게 보여줍니다. 하만의 개인적 자존심이 한 민족의 생존을 위협하는 대학살 계획으로 확대되는 과정은, 악이 얼마나 빠르게 번져나갈 수 있는지를 경고합니다. 동시에 신앙의 원칙을 지키려는 모르드개의 모습은 타협하지 않는 믿음이 때로는 큰 대가를 요구할 수 있음을 보여줍니다.\n\n오늘날에도 우리는 크고 작은 하만들을 마주합니다. 권력을 남용하고, 자신과 다른 이들을 배척하며, 증오를 부추기는 목소리들이 여전히 존재합니다. 그러나 하나님은 역사의 주관자이십니다. 보이지 않는 곳에서도 당신의 백성을 지키시고, 악한 계획을 무너뜨리시는 분이십니다. 모르드개처럼 신앙의 원칙을 지키는 용기와, 다가올 위험 앞에서도 하나님을 신뢰하는 믿음이 우리에게 필요합니다.', E'오늘의 핵심\n한 사람의 교만과 증오가 민족 전체의 생존을 위협하는 대학살 계획으로 번지지만, 하나님은 보이지 않는 곳에서 당신의 백성을 위한 구원을 예비하고 계십니다.\n\n묵상 질문\n1. 신앙의 원칙을 지키기 위해 불이익을 감수한 적이 있으신가요?\n2. 내 주변에서 약자를 향한 편견과 증오의 목소리를 들을 때 어떻게 반응하시나요?\n3. 위기의 순간에도 하나님께서 역사를 주관하신다는 믿음을 갖고 있으신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-05', E'유다 민족의 위기 (에스더 4장)', E'에스더 4장', E'페르시아 제국 전역에 유다 민족을 멸절하라는 조서가 내려진 후, 모르드개는 굵은 베 옷을 입고 재를 뒤집어쓴 채 대궐 문 앞에서 대성통곡합니다. 이는 단순한 개인적 슬픔의 표현이 아니라, 민족 전체가 직면한 절체절명의 위기를 하나님 앞에 아뢰는 간절한 호소였습니다. 각 지방의 유다인들도 금식하며 울부짖으며 재에 누워 하나님께 부르짖었습니다.\n\n왕궁 안의 에스더는 처음에는 이 위기의 전모를 알지 못했습니다. 하지만 모르드개를 통해 하만의 음모와 민족 말살 계획을 알게 되자, 그녀 앞에는 생명을 건 선택이 놓입니다. 당시 페르시아 법에 따르면 왕이 부르지 않았는데 왕 앞에 나아가는 것은 죽음을 의미했습니다. 에스더가 왕에게 나아가지 못한 지도 이미 삼십 일이 지난 상황이었습니다.\n\n모르드개는 에스더에게 중요한 메시지를 전합니다. "네가 왕후의 자리를 얻은 것이 이 때를 위함이 아닌지 누가 알겠느냐"(에 4:14). 이 말씀은 우연처럼 보이는 일들 속에도 하나님의 섭리가 있음을 깨닫게 합니다. 에스더가 왕후가 된 것은 단지 개인의 영광을 위해서가 아니라, 바로 이 위기의 순간에 민족을 구원할 도구로 쓰임받기 위함이었습니다.\n\n에스더의 결단은 놀랍습니다. "죽으면 죽으리이다"라는 각오와 함께 그녀는 수산성의 모든 유다인들에게 삼 일간 금식을 요청합니다. 이는 단순히 용기를 내는 것이 아니라, 하나님께 전적으로 의지하며 나아가는 믿음의 결단이었습니다. 왕후의 화려한 지위도, 왕궁의 안전도 그녀가 하나님 앞에서 받은 소명을 회피하는 이유가 될 수 없었습니다.\n\n오늘 우리도 각자의 자리에서 하나님의 부르심을 받고 있습니다. 때로는 위험하고 불편한 선택을 해야 할 때도 있습니다. 그러나 하나님께서는 우리를 지금 이 자리에 ''이 때를 위하여'' 세우셨습니다. 두려움 앞에서도 기도로 나아가며, 하나님의 뜻을 분별하고 순종하는 믿음의 결단이 필요합니다.', E'오늘의 핵심\n민족의 생사가 걸린 위기 앞에서 에스더는 "죽으면 죽으리이다"라는 믿음의 결단으로 금식 기도하며 하나님께서 자신을 왕후로 세우신 목적을 깨닫고 순종합니다.\n\n묵상 질문\n1. 하나님께서 나를 지금 이 자리에 두신 목적은 무엇일까요?\n2. 두려움과 안전 사이에서 믿음의 결단을 미루고 있는 일은 없나요?\n3. 위기의 순간에 먼저 기도와 금식으로 하나님께 나아가고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-07', E'유다 민족의 위기 (에스더 5장)', E'에스더 5장', E'삼일 간의 금식 기도가 끝났습니다. 에스더는 왕후의 예복을 입고 왕궁 안뜰에 섭니다. 왕이 부르지 않았는데 왕 앞에 나아가면 죽을 수도 있는 페르시아의 법 앞에서, 에스더는 생명을 건 발걸음을 내딛습니다. 그런데 놀라운 일이 일어납니다. 왕이 에스더를 보고 금 규를 내민 것입니다. 이는 단순한 호의가 아니라 하나님의 섭리하심이었습니다. 왕은 나라의 절반이라도 주겠다고 말할 정도로 에스더에게 호의를 보입니다.\n\n그러나 에스더는 서두르지 않습니다. 당장이라도 하만의 악한 계획을 고발하고 싶었겠지만, 그녀는 왕과 하만을 잔치에 초대합니다. 첫 번째 잔치에서도 왕이 소원을 물었을 때, 에스더는 다시 한 번 내일의 잔치로 미룹니다. 이는 단순한 망설임이 아니라 지혜로운 기다림이었습니다. 하나님의 때를 분별하며 상황을 신중히 살피는 믿음의 행동이었습니다.\n\n한편 하만은 왕후의 잔치에 초대받은 영광에 도취되어 의기양양해합니다. 그러나 대궐 문에서 여전히 자신에게 절하지 않는 모르드개를 보자 분노가 치밀어 오릅니다. 집에 돌아온 하만은 자신의 부와 영광을 자랑하면서도 "유다 사람 모르드개가 대궐 문에 앉은 것을 보는 동안에는 이 모든 일이 만족하지 아니하도다"라고 말합니다. 그의 아내와 친구들은 오십 규빗 높이의 나무를 세워 모르드개를 매달라고 부추깁니다.\n\n하만의 모습은 교만이 어떻게 사람을 파멸로 이끄는지를 보여줍니다. 가진 것이 아무리 많아도 한 사람의 경배를 받지 못한다는 이유로 모든 것이 무의미하다고 느끼는 그의 마음은 이미 병들어 있었습니다. 반면 에스더는 왕후의 권위를 가지고도 겸손히 하나님의 때를 기다리며 지혜롭게 행동합니다.\n\n우리도 때로는 즉각적인 해결을 원하며 조급해하지만, 하나님께서는 기다림을 통해 더 완전한 구원을 예비하십니다. 에스더의 신중한 기다림과 하만의 성급한 교만이 대조를 이루는 이 장면에서, 우리는 하나님의 때를 분별하며 겸손히 나아가는 지혜를 배우게 됩니다.', E'오늘의 핵심\n에스더는 생명의 위험을 무릅쓰고 왕 앞에 나아갔지만, 성급히 행동하지 않고 하나님의 때를 기다리며 지혜롭게 상황을 이끌어갑니다.\n\n묵상 질문\n1. 급한 상황에서도 하나님의 때를 기다리며 지혜롭게 행동하고 있습니까?\n2. 하만처럼 가진 것에 만족하지 못하고 작은 일에 분노하는 마음은 없습니까?\n3. 에스더처럼 기도 후에도 신중하게 한 걸음씩 나아가는 믿음이 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-08', E'위대한 구원 (에스더 6장)', E'에스더 6장', E'그 날 밤, 왕이 잠을 이루지 못합니다. 불면의 밤은 누구에게나 괴로운 시간이지만, 하나님께서는 이 불면의 시간마저 섭리의 도구로 사용하십니다. 왕은 역대 일기를 읽게 하는데, 그 속에서 잊혀졌던 모르드개의 충성이 발견됩니다. 왕을 암살하려던 음모를 고발했던 그 공로가 아무런 보상 없이 묻혀 있었던 것입니다.\n\n바로 그 시각, 뜰에는 하만이 서 있습니다. 모르드개를 처형하기 위해 이른 아침부터 왕궁에 나온 것입니다. 왕이 "왕이 존귀하게 하기를 원하는 사람에게 어떻게 하여야 하겠느냐"고 묻자, 하만은 그것이 자신을 가리키는 말로 착각합니다. 왕복과 왕관, 그리고 왕의 말을 타고 성중을 행진하는 영광스러운 장면을 그려내며 답합니다.\n\n그러나 하나님의 반전은 놀랍습니다. 하만이 제안한 그 모든 영예가 정작 그가 죽이려 했던 모르드개에게 돌아가게 됩니다. 더욱이 하만 자신이 모르드개에게 왕복을 입히고, 그를 말에 태워 "왕이 존귀하게 하시기를 원하시는 사람에게는 이같이 할 것이라"고 외쳐야 했습니다. 교만의 정점에서 굴욕의 나락으로 떨어지는 순간이었습니다.\n\n하만의 아내와 지혜로운 친구들조차 "모르드개가 과연 유다 사람의 후손이면... 분명히 그 앞에 엎드러지리이다"(13절)라고 예언합니다. 그들도 이제 하나님의 백성을 대적하는 일의 무모함을 깨닫게 된 것입니다. \n\n하나님의 섭리는 우연처럼 보이는 일들을 통해 이루어집니다. 왕의 불면, 잊혀진 기록의 발견, 하만의 때맞춘 등장 - 이 모든 것이 하나님의 손길 안에서 정확한 때에 일어났습니다. 인간의 교만은 무너지고, 겸손한 자는 높아지며, 하나님의 백성을 해하려던 계획은 오히려 그들의 영광이 되는 길로 바뀌어갑니다.', E'오늘의 핵심\n하나님께서는 왕의 불면의 밤과 잊혀진 역사 기록을 통해 교만한 하만을 낮추시고 충성된 모르드개를 높이시는 놀라운 반전의 섭리를 보여주십니다.\n\n묵상 질문\n1. 내 삶의 우연처럼 보이는 일들 속에서 하나님의 섭리를 발견한 적이 있나요?\n2. 교만이 스스로 파놓은 함정이 되었던 경험이 있다면 무엇인가요?\n3. 때로는 잊혀진 것 같은 나의 충성과 헌신도 하나님께서 기억하고 계심을 믿고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-09', E'위대한 구원 (에스더 7장)', E'에스더 7장', E'둘째 날 잔치에서 왕이 다시 에스더의 소청을 물었을 때, 에스더는 마침내 준비된 때가 왔음을 알았습니다. "내 소청대로 내 생명을 내게 주시고 내 요구대로 내 민족을 내게 주소서"(3절). 에스더의 이 간청은 단순한 개인의 탄원이 아니었습니다. 자신의 민족 전체의 운명이 걸린, 생사를 가르는 순간이었습니다.\n\n에스더는 왕 앞에서 충격적인 진실을 드러냅니다. 자신과 자신의 민족이 "팔려서 죽임과 도륙함과 진멸함을 당하게 되었다"는 것입니다. 노예로 팔리는 것과는 차원이 다른, 완전한 멸절의 위기였습니다. 그리고 바로 그 순간, 에스더는 "대적과 원수는 이 악한 하만이니이다"라고 선언합니다. 왕의 총애를 받던 하만이 실은 왕후와 그 민족을 죽이려 한 반역자였음이 밝혀진 것입니다.\n\n진실이 드러나자 상황은 급반전됩니다. 왕의 분노 앞에서 하만은 두려워 떨며 에스더에게 생명을 구걸하지만, 이미 때는 늦었습니다. 아이러니하게도 하만은 자신이 모르드개를 위해 준비한 그 나무에 달려 죽음을 맞이합니다. 악을 도모한 자가 자신이 판 함정에 빠진 것입니다.\n\n하나님의 섭리는 이렇게 역사 속에서 일하십니다. 인간의 눈에는 보이지 않는 하나님의 손길이 에스더를 왕후의 자리에 앉히셨고, 적절한 때에 진실을 드러내게 하셨습니다. 우리 삶에도 하만과 같은 대적이 있을 수 있습니다. 그러나 하나님은 당신의 백성을 지키시며, 악한 계획을 선으로 바꾸시는 분입니다. 에스더처럼 믿음과 지혜로 준비하며 기다릴 때, 하나님께서 정하신 때에 구원의 역사를 이루실 것입니다.', E'오늘의 핵심\n하나님은 에스더를 통해 유다 민족을 구원하시고, 악을 도모한 하만을 그가 판 함정에 빠뜨리심으로써 당신의 공의를 나타내셨습니다.\n\n묵상 질문\n1. 에스더처럼 결정적인 순간에 진실을 말할 용기가 내게 있나요?\n2. 하나님께서 악한 계획을 무너뜨리시는 것을 경험한 적이 있나요?\n3. 위기의 때에도 하나님의 섭리를 신뢰하며 기다릴 수 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-10', E'욥의 고난과 탄식 (욥기 1장)', E'욥기 1장', E'욥기는 족장 시대를 배경으로 하는 가장 오래된 지혜서 중 하나로, 의인의 고난이라는 인류의 영원한 질문을 다룹니다. 우스 땅에 살던 욥은 "온전하고 정직하여 하나님을 경외하며 악에서 떠난 자"(욥 1:1)로 소개됩니다. 일곱 아들과 세 딸, 그리고 동방에서 가장 많은 재산을 소유한 그는 물질적으로나 영적으로나 복된 삶을 살고 있었습니다. 특히 욥기는 그가 자녀들을 위해 정기적으로 번제를 드렸다는 사실을 통해 그의 신앙이 형식적이지 않고 가족 전체를 아우르는 진실한 것임을 보여줍니다.\n\n그런데 하늘의 회의 장면이 우리에게 보여주는 것은 욥의 시련이 우연히 일어난 것이 아니라는 사실입니다. 사탄은 욥의 신앙이 그가 받은 축복 때문이라고 주장하며, 하나님의 보호막이 사라지면 그가 하나님을 저주할 것이라고 도전합니다. 하나님께서는 욥의 소유물에 대한 사탄의 시험을 허락하시되, 그의 생명은 해치지 못하도록 제한을 두십니다. 이는 하나님께서 여전히 주권적으로 모든 것을 통치하고 계심을 보여줍니다.\n\n하루아침에 욥에게 닥친 재앙은 상상을 초월합니다. 스바 사람들의 약탈, 하늘에서 떨어진 불, 갈대아 사람들의 침략이 연이어 일어나고, 급기야 자녀들이 모두 한순간에 죽는 비극이 발생합니다. 그러나 욥의 반응은 놀랍습니다. 그는 애통해하면서도 "주신 이도 여호와시요 거두신 이도 여호와시오니 여호와의 이름이 찬송을 받으실지니이다"라고 고백합니다. 성경은 이 모든 일에 욥이 하나님을 향하여 원망하지 않았다고 증언합니다. 고난 속에서도 하나님의 주권을 인정하고 예배하는 욥의 모습은 우리에게 진정한 신앙이 무엇인지를 가르쳐줍니다.', E'오늘의 핵심\n하나님을 경외하던 의인 욥에게 하루아침에 모든 재산과 자녀를 잃는 극심한 고난이 찾아오지만, 그는 여전히 하나님의 주권을 인정하며 예배하는 놀라운 신앙의 모습을 보여줍니다.\n\n묵상 질문\n1. 나의 신앙은 받은 축복에 기초한 것인가, 아니면 하나님 자체를 사랑하는 것인가요?\n2. 극심한 고난 속에서도 하나님을 예배할 수 있는 신앙의 깊이를 어떻게 길러갈 수 있을까요?\n3. 오늘 나에게 닥친 어려움 속에서 하나님의 주권을 인정하는 구체적인 고백은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-11', E'욥의 고난과 탄식 (욥기 2장)', E'욥기 2장', E'하늘의 회의가 다시 열립니다. 욥이 첫 번째 시험을 통과한 후에도 사탄은 포기하지 않고 하나님 앞에 나아옵니다. 하나님께서는 욥이 여전히 자신의 온전함을 굳게 지켰음을 말씀하시지만, 사탄은 "가죽으로 가죽을 바꾸오니 사람이 그의 모든 소유물로 자기의 생명을 바꾸올지라"라며 더 깊은 시험을 요구합니다. 재산과 자녀를 잃는 것과 자신의 생명이 위협받는 것은 차원이 다른 문제라는 주장입니다.\n\n하나님께서는 욥의 생명만은 해하지 말라는 조건으로 사탄의 요구를 허락하십니다. 곧 욥의 발바닥에서 정수리까지 악성 종기가 나게 되고, 그는 재 가운데 앉아 질그릇 조각으로 몸을 긁는 비참한 신세가 됩니다. 육체적 고통이 극에 달한 가운데, 그의 아내마저 "하나님을 욕하고 죽으라"고 말합니다. 가장 가까운 사람으로부터 받는 이런 말은 욥에게 또 다른 상처가 되었을 것입니다.\n\n그러나 욥의 대답은 놀랍습니다. "우리가 하나님께 복을 받았은즉 화도 받지 아니하겠느냐." 이는 단순한 체념이 아니라 하나님의 주권을 인정하는 깊은 신앙고백입니다. 성경은 "이 모든 일에 욥이 입술로 범죄하지 아니하니라"라고 기록하여 그의 신앙이 진실됨을 증언합니다.\n\n멀리서 소식을 들은 세 친구가 찾아옵니다. 그들은 욥을 위로하려 왔지만, 그의 모습이 알아볼 수 없을 정도로 변한 것을 보고 말을 잃습니다. 칠 일 동안 그와 함께 앉아 있으면서도 한마디도 하지 못하는 그들의 모습은, 고난 앞에서 인간의 언어가 얼마나 무력한지를 보여줍니다. 때로는 침묵의 동행이 가장 깊은 위로가 될 수 있음을 그들의 초기 모습이 가르쳐줍니다.', E'오늘의 핵심\n욥의 고난이 육체적 차원으로 확대되는 가운데, 그는 하나님의 주권을 인정하며 여전히 입술로 범죄하지 않는 믿음의 본을 보여줍니다.\n\n묵상 질문\n1. 가장 가까운 사람으로부터 상처받을 때, 나는 어떻게 반응하나요?\n2. 고난 중에도 하나님의 주권을 인정한다는 것은 무엇을 의미할까요?\n3. 고통받는 이웃과 함께하는 침묵의 동행을 실천해본 경험이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-12', E'욥의 고난과 탄식 (욥기 3장)', E'욥기 3장', E'욥기 3장은 극심한 고난 속에서 터져 나온 욥의 처절한 탄식을 그대로 보여줍니다. 침묵을 지키던 욥이 마침내 입을 열어 자기가 태어난 날을 저주하는 모습은 그의 고통이 얼마나 깊은지를 생생하게 전달합니다. 욥은 자신이 태어난 날이 아예 없었기를, 그 날이 영원한 어둠에 묻혔기를 간절히 바랍니다. 태어나자마자 죽었더라면, 아니 아예 태어나지 않았더라면 이런 고통을 겪지 않았을 것이라는 그의 한탄은 인간이 감당할 수 있는 고통의 한계를 넘어섰음을 보여줍니다.\n\n주목할 것은 욥이 하나님을 원망하거나 저주하지 않고 자신의 생일을 저주한다는 점입니다. 이는 여전히 하나님을 경외하는 마음을 잃지 않았으면서도, 동시에 견딜 수 없는 고통 속에서 신음하는 의인의 모습을 보여줍니다. 욥은 죽음을 평안과 쉼의 장소로 묘사하며, 거기서는 악한 자도 소요를 그치고 피곤한 자도 쉼을 얻는다고 말합니다. 심지어 종도 상전에게서 자유롭게 된다는 그의 표현은 현재 자신이 겪는 고통이 얼마나 참혹한지를 역설적으로 드러냅니다.\n\n욥의 탄식은 단순한 절망의 외침이 아닙니다. 그는 "하나님에게 둘러싸여 길이 아득한 사람"이라는 표현을 통해 자신의 고난이 하나님과 무관하지 않음을 인식하고 있습니다. 평온도, 안일도, 휴식도 없이 오직 불안만이 있다는 욥의 고백은 의인이 겪는 설명할 수 없는 고난의 실재를 보여줍니다. 이러한 욥의 솔직한 탄식은 오히려 하나님과의 관계가 여전히 살아있음을 증명합니다. 진정한 신앙은 고통 속에서도 하나님께 자신의 모든 감정을 토로할 수 있는 정직함에서 시작됩니다.', E'오늘의 핵심\n극심한 고난 속에서 욥은 자신의 생일을 저주하며 깊은 탄식을 쏟아내지만, 여전히 하나님을 의식하며 그분 앞에서 자신의 고통을 정직하게 표현합니다.\n\n묵상 질문\n1. 욥처럼 고통 속에서도 하나님께 정직하게 나아갈 수 있는 용기가 내게 있나요?\n2. 내 삶의 어두운 순간에도 하나님이 함께하심을 어떻게 기억할 수 있을까요?\n3. 고난 중에 있는 이웃에게 내가 전할 수 있는 위로는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-14', E'엘리바스는 욥을 위로하기보다는 정죄하기 시작합니다 (욥기 4장)', E'욥기 4장', E'욥에게 찾아온 세 친구는 처음 그의 참혹한 모습을 보고 말을 잃었습니다. 너무나 극심한 고통 앞에서 차마 입을 열지 못한 채 일주일을 함께 앉아 있었습니다. 그 침묵의 시간은 어쩌면 가장 진실한 위로였을지 모릅니다. 그런데 일주일이 지나고 데만 사람 엘리바스가 입을 열면서 상황이 달라집니다.\n\n엘리바스는 욥이 과거에 많은 사람을 훈계하고 약한 자를 붙들어 주었던 것을 상기시킵니다. 그러면서 정작 본인에게 고난이 닥치자 흔들리는 모습을 지적합니다. 이어서 그는 "죄 없이 망한 자가 누구인가"라는 질문을 던지며, 욥의 고난 뒤에는 분명 숨겨진 죄가 있을 것이라고 암시합니다. 악을 심은 자는 그대로 거둔다는 인과응보의 논리로 욥을 몰아세우는 것입니다.\n\n더 나아가 엘리바스는 자신이 받은 환상을 근거로 인간의 본질적인 연약함과 죄성을 강조합니다. 하나님 앞에서 인간은 누구도 의롭거나 깨끗할 수 없다는 것입니다. 그의 말은 신학적으로 틀리지 않았습니다. 하지만 문제는 그 옳은 말이 지금 이 사람에게 필요한 말이냐는 것입니다. 재 위에 앉아 온몸이 부스럼투성이인 친구에게 필요한 것은 신학적 분석이 아니라, 함께 아파하는 마음이었습니다.\n\n엘리바스의 태도는 오늘날 우리의 모습을 돌아보게 합니다. 고통받는 이웃을 만날 때, 우리는 종종 그 고통의 원인을 먼저 찾으려 합니다. "하나님의 뜻이 있을 거야", "다 이유가 있겠지"라는 말로 섣불리 해석하려 합니다. 하지만 욥기는 우리에게 보여줍니다. 인간의 고난은 단순한 인과관계로 설명될 수 없으며, 때로는 침묵의 동행이 많은 말보다 더 큰 위로가 된다는 것을 말입니다.', E'오늘의 핵심\n엘리바스는 욥의 고난을 인과응보의 논리로 해석하며, 고통받는 친구를 위로하기보다 정죄하는 실수를 범합니다.\n\n묵상 질문\n1. 내가 고통받는 사람에게 건네는 말은 위로입니까, 아니면 또 하나의 짐입니까?\n2. 옳은 말보다 따뜻한 마음이 먼저일 때는 언제일까요?\n3. 오늘 내 곁에서 아파하는 사람과 어떻게 함께할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-15', E'엘리바스는 욥을 위로하기보다는 정죄하기 시작합니다 (욥기 5장)', E'욥기 5장', E'엘리바스의 말은 4장에 이어 5장에서도 계속됩니다. 그는 이제 더욱 확신에 찬 어조로 욥에게 권면을 쏟아냅니다. "미련한 자가 뿌리 내리는 것을 보고 그의 집을 당장에 저주하였노라"(5:3)는 그의 말에는 욥의 고난을 죄의 결과로 단정하는 냉정함이 담겨 있습니다. 엘리바스는 자신이 목격한 악인의 멸망 사례들을 나열하면서, 욥의 현재 상황이 바로 그런 심판의 결과임을 암시합니다.\n\n특히 주목할 것은 엘리바스가 제시하는 해결책입니다. "나라면 하나님을 찾겠고 내 일을 하나님께 의탁하리라"(5:8)는 그의 권면은 얼핏 신앙적으로 들립니다. 그는 하나님의 위대하심과 구원의 능력을 길게 설명하며, 징계를 받아들이고 회개하면 모든 것이 회복될 것이라고 약속합니다. "하나님께 징계 받는 자에게는 복이 있나니"(5:17)라는 그의 말은 그 자체로는 옳은 진리입니다.\n\n하지만 엘리바스의 조언이 놓치고 있는 것이 있습니다. 그는 욥의 고난을 모두 죄의 결과로 보는 단순한 인과응보의 틀에 갇혀 있습니다. 고난에는 여러 이유가 있고, 때로는 의인도 이유를 알 수 없는 시련을 겪는다는 신비를 이해하지 못합니다. 그의 신학은 정확하지만, 그 적용은 잘못되었습니다. 마치 의사가 진단도 제대로 하지 않고 처방전을 내리는 것과 같습니다.\n\n엘리바스가 약속하는 회복의 청사진은 매력적입니다. 자손의 번성, 장수, 평안한 삶 - 이 모든 것을 그는 회개의 대가로 제시합니다. 하지만 이는 오히려 욥에게 더 큰 좌절을 안겨줍니다. 왜냐하면 욥은 자신이 무엇을 잘못했는지 알지 못하기 때문입니다. 친구의 확신에 찬 정죄는 고통받는 의인에게 또 다른 짐이 되어버렸습니다.\n\n우리도 때로 엘리바스처럼 성급한 상담자가 되곤 합니다. 고통의 원인을 단순화하고, 검증되지 않은 공식으로 해답을 제시합니다. 하지만 하나님의 섭리는 우리의 이해를 넘어서며, 고난의 신비는 간단한 방정식으로 풀리지 않습니다. 진정한 위로는 모든 답을 아는 척하는 것이 아니라, 답을 모르는 채로도 함께 있어주는 것에서 시작됩니다.', E'오늘의 핵심\n엘리바스는 욥의 고난을 죄의 결과로 단정하며 회개를 촉구하지만, 이는 고난의 복잡한 실체를 이해하지 못한 성급한 판단이었습니다.\n\n묵상 질문\n1. 내가 타인의 고통을 너무 단순한 인과관계로 설명하려 한 적은 없나요?\n2. 하나님의 섭리가 내 이해를 넘어선다는 것을 인정할 수 있나요?\n3. 답을 모르는 상황에서도 사랑으로 함께하는 것이 진정한 위로가 될 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-16', E'욥과 빌닷의 두 번째 논쟁 (욥기 18장)', E'욥기 18장', E'빌닷이 두 번째로 입을 열어 욥을 향해 더욱 거센 공격을 퍼붓습니다. 그의 말은 악인의 운명에 대한 일반론처럼 포장되어 있지만, 실제로는 욥의 현재 상황 하나하나를 악인의 결말에 대입시키는 잔인한 정죄입니다. "악인의 빛은 꺼지고 그의 불꽃은 빛나지 않을 것"(욥 18:5)이라는 빌닷의 선언은, 자녀를 잃고 재산을 잃으며 건강까지 잃은 욥의 처지를 직접적으로 겨냥하고 있습니다. 발이 그물에 걸리고, 덫에 치이며, 뿌리가 마르고 가지가 시든다는 묘사들은 욥의 고통을 더욱 생생하게 상기시키는 말들입니다.\n\n빌닷의 신학은 단순명료합니다. 고난은 죄의 결과이고, 욥이 이런 고난을 당하는 것은 그가 악인이기 때문이라는 것입니다. 이러한 인과응보의 공식은 당시 지혜 전통에서 널리 받아들여지던 관점이었습니다. 그러나 빌닷은 이 전통적 지혜를 기계적으로 적용하면서 고통받는 친구를 향한 최소한의 연민마저 잃어버렸습니다. 그의 말 속에는 욥을 향한 위로나 격려는 찾아볼 수 없고, 오직 차가운 정죄와 심판만이 남아 있습니다.\n\n더욱 안타까운 것은 빌닷이 하나님의 공의를 변호한다고 생각하면서 실제로는 하나님의 성품을 왜곡하고 있다는 점입니다. 그는 하나님을 단순한 심판자로만 축소시키고, 고난 중에도 함께하시는 하나님의 긍휼과 사랑을 놓치고 있습니다. 빌닷의 신학적 확신은 그로 하여금 친구의 아픔을 공감하지 못하게 만들었고, 오히려 그 아픔에 소금을 뿌리는 결과를 낳았습니다.\n\n우리도 때로는 빌닷처럼 행동합니다. 누군가의 어려움을 보면서 "그럴 만한 이유가 있겠지"라고 쉽게 판단하거나, 고통의 원인을 분석하느라 정작 그 사람의 아픔에 공감하지 못할 때가 있습니다. 하나님께서는 우리가 서로의 짐을 나누어지고, 우는 자들과 함께 울기를 원하십니다. 진정한 지혜는 모든 것을 설명하려는 것이 아니라, 때로는 침묵 가운데 함께 아파하는 것임을 빌닷의 실패를 통해 배우게 됩니다.', E'오늘의 핵심\n빌닷은 전통적인 인과응보 신학에 갇혀 고통받는 친구를 정죄하며, 하나님의 긍휼과 사랑을 놓치는 잘못된 위로자의 모습을 보여줍니다.\n\n묵상 질문\n1. 하나님의 공의와 사랑을 균형 있게 이해하려면 어떤 자세가 필요할까요?\n2. 고통받는 이웃에게 섣부른 판단 대신 진정한 위로를 전하려면 무엇을 먼저 해야 할까요?\n3. 내가 가진 신앙적 확신이 때로는 사랑 없는 정죄가 되지 않으려면 어떻게 해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-17', E'욥과 빌닷의 두 번째 논쟁 (욥기 19장)', E'욥기 19장', E'욥의 외침은 점점 더 절박해집니다. "너희가 내 마음을 괴롭히며 말로 나를 짓부수기를 어느 때까지 하겠느냐"는 욥의 탄식은 육체의 고통보다 친구들의 정죄가 더 큰 상처임을 보여줍니다. 욥은 하나님께서 자신을 억울하게 하시고 그물로 에워싸셨다고 토로하면서도, 여전히 하나님께 부르짖고 있습니다. 이는 고통 속에서도 하나님과의 관계를 포기하지 않는 신앙인의 모습을 보여줍니다.\n\n욥이 겪는 고립의 깊이는 상상을 초월합니다. 형제들이 멀리 떠나고, 친척은 그를 버렸으며, 집에 머무는 자들조차 그를 낯선 사람으로 여깁니다. 아내는 그의 숨결을 싫어하고, 어린아이들까지 그를 조롱합니다. 가장 사랑했던 사람들이 원수가 되었다는 고백은 욥이 경험하는 철저한 외로움을 생생하게 전해줍니다. "내 피부와 살이 뼈에 붙었고 남은 것은 겨우 잇몸뿐"이라는 표현은 극도로 쇠약해진 그의 육체적 상태까지 보여줍니다.\n\n그러나 바로 이 절망의 바닥에서 놀라운 신앙고백이 터져 나옵니다. "내가 알기에는 나의 대속자가 살아 계시니 마침내 그가 땅 위에 서실 것이라"는 선언은 구약성경에서 가장 위대한 믿음의 고백 중 하나입니다. 모든 것을 잃고 아무도 자신을 이해해주지 않는 상황에서, 욥은 오히려 하나님만이 자신의 편이 되어주실 분임을 확신합니다. 육체가 썩은 후에도 하나님을 뵈올 것이라는 부활 신앙의 씨앗까지 발견됩니다.\n\n욥의 이야기는 우리에게 중요한 통찰을 제공합니다. 때로 우리도 아무도 이해해주지 않는 고통의 시간을 지날 수 있습니다. 가장 가까운 사람들조차 등을 돌릴 때, 그 고립감은 견디기 어려울 것입니다. 그러나 욥이 보여주듯, 바로 그 순간이 하나님께서 우리의 유일한 대속자이심을 가장 깊이 경험하는 때가 될 수 있습니다. 사람의 위로가 끊어진 곳에서 하나님의 위로가 시작되며, 모든 희망이 사라진 듯 보일 때 영원한 소망이 솟아납니다.', E'오늘의 핵심\n철저한 고립과 절망 속에서도 욥은 살아계신 대속자 하나님을 고백하며, 고통의 바닥에서 오히려 부활의 소망을 발견합니다.\n\n묵상 질문\n1. 나를 이해해주는 사람이 아무도 없다고 느낄 때, 하나님은 어떤 분으로 다가오시나요?\n2. 욥처럼 극한의 고통 속에서도 "나의 대속자가 살아 계시니"라고 고백할 수 있는 믿음은 어디서 올까요?\n3. 고립감과 외로움 속에 있는 이웃에게 내가 할 수 있는 위로의 손길은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-18', E'욥과 소발의 두 번째 논쟁', E'욥기 20장', E'욥의 친구들은 욥이 심한 고난 가운데 있음에도 불구하고, 점차 욥에 대한 위로보다는 정죄와 자기 논리의 관철에 집중하고 있습니다. 소발의 두 번째 발언에 대해 욥은 눈앞에 놓인 현실을 직시하라고 말합니다. 욥은 세상에 가득한 모순을 열거하며, 의인은 번성하고 악인은 쇠하게 되는 것이 진리이기는 하나 현실에는 꼭 그렇지 않은 경우도 많이 있다고 주장합니다.\n사실, 친구들의 변론이 전혀 근거 없거나 완전히 틀린 말은 아니었습니다. 때로는 그들이 한 말들이 귀한 진리이기도 합니다. 그러나 인간의 고난과 죄의 문제는 인간들이 논쟁을 통해서 해결할 수 있는 것이 아닙니다. 하나님께서 의로운 자를 구원하시고 불의한 자를 심판하시는 것은 성경 전체를 관통하는 주제 가운데 하나이지만 하나님은 인생들의 논리로 다 설명할 수 있는 분이 아닙니다. 비록 이 세상에 의인이 고난을 당하고 악인이 득세하는 부조리가 가득하다고 할지라도 그것으로 인해 하나님의 거룩하심과 공의로우심에 흠이 갈 수는 없습니다. 하나님께서는 모든 일에 정한 때가 있으신 분이며, 하나님의 때에 모든 선과 악이 명명백백하게 드러날 것이기 때문입니다.', E'오늘의 핵심\n욥의 형편을 진지하게 이해하려 하지 않는 친구들. 그들의 마음에는 가장 중요한 욥에 대한 사랑과 배려가 없었습니다.\n\n묵상 질문\n하나님은 우리의 고통 속에서도 우리를 정죄하지 않고 함께하시나요?\n내가 다른 사람의 고난 앞에서 옳은 말보다 위로를 먼저 건네고 있나요?\n내 논리가 맞다고 생각할 때, 상대의 현실과 마음을 제대로 보고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-19', E'욥과 엘리바스의 세 번째 논쟁 (욥기 22장)', E'욥기 22장', E'엘리바스가 세 번째로 입을 엽니다. 이번에는 더 이상 논리적인 근거를 대지 못한 채, 욥이 저지르지도 않은 죄들을 구체적으로 나열하기 시작합니다. 형제를 까닭 없이 볼모로 잡고, 헐벗은 자의 의복을 벗기며, 목마른 자에게 물을 주지 않고, 과부와 고아를 학대했다는 것입니다. 하나님께서 직접 "온전하고 정직하여 하나님을 경외하며 악에서 떠난 자"라고 평가하신 욥에게 이런 비난은 명백한 거짓입니다. 엘리바스는 ''고통받는 사람은 반드시 죄를 지었기 때문''이라는 자신의 신학적 공식을 지키기 위해 사실을 왜곡하고 있습니다.\n\n엘리바스의 논리는 단순합니다. "네 악이 크지 아니하냐 네 죄악이 끝이 없느니라"(5절). 그는 욥의 고난이 곧 욥의 죄악의 증거라고 단정합니다. 그러나 이런 인과응보의 공식은 하나님의 주권적 섭리를 제한하는 위험한 사고입니다. 하나님께서는 때로 의인에게도 고난을 허락하시며, 그 고난을 통해 더 깊은 믿음으로 인도하십니다.\n\n더 아이러니한 것은 엘리바스가 욥에게 회개를 촉구하며 제시하는 약속들입니다. "네가 만일 전능자에게로 돌아가면 네가 지음을 받을 것이며"(23절), "전능자가 네 보화가 되시며 네게 고귀한 은이 되시리니"(25절). 그는 욥이 회개하면 모든 것이 회복될 것이라고 말합니다. 그러나 욥은 이미 하나님 앞에서 정직한 삶을 살아왔고, 지금도 하나님을 떠난 적이 없습니다.\n\n엘리바스의 말은 겉으로는 경건해 보이지만, 실제로는 하나님의 성품을 왜곡하고 있습니다. 그는 하나님을 인간의 행위에 따라 기계적으로 반응하시는 분으로 축소시킵니다. 그러나 성경이 보여주는 하나님은 인간의 공식으로 설명할 수 없는 주권적이고 신비로운 분이십니다. 우리가 이해할 수 없는 고난 속에서도 하나님의 선하신 뜻이 있음을 믿는 것, 그것이 진정한 믿음입니다.', E'오늘의 핵심\n엘리바스는 욥이 저지르지도 않은 죄들을 나열하며 정죄하지만, 이는 고난을 단순한 인과응보로 설명하려는 잘못된 시도입니다.\n\n묵상 질문\n1. 나는 다른 사람의 고난을 볼 때 성급하게 그 원인을 판단하고 있지는 않나요?\n2. 하나님을 나의 신학적 공식 안에 가두려 하지는 않았나요?\n3. 거짓된 정죄 앞에서도 하나님의 공의를 신뢰할 수 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-21', E'욥과 엘리바스의 세 번째 논쟁 (욥기 23장)', E'욥기 23장', E'엘리바스의 세 번째 변론은 이제 욥을 향한 거짓 고발로 가득 차 있습니다. 더 이상 논리적 근거를 찾을 수 없게 되자, 그는 욥이 저지르지도 않은 죄들을 나열하며 정죄합니다. 이런 억울한 공격 앞에서 욥은 놀랍게도 친구들과의 논쟁을 멈추고 오직 하나님께로 시선을 돌립니다. "내가 어찌하면 하나님을 발견하고 그의 처소에 나아가랴"(욥 23:3). 욥의 간절함이 이 외침에 고스란히 담겨 있습니다.\n\n욥은 하나님을 찾아 앞으로 가도, 뒤로 가도, 왼쪽에서도 오른쪽에서도 그분을 만날 수 없다고 고백합니다. 하나님의 침묵이 계속되는 것입니다. 그런데 바로 이 절망적인 상황 속에서 놀라운 신앙의 고백이 터져 나옵니다. "그러나 내가 가는 길을 그가 아시나니 그가 나를 단련하신 후에는 내가 순금 같이 되어 나오리라." 욥은 하나님이 보이지 않아도, 응답하지 않으셔도, 자신의 모든 길을 아시는 하나님을 신뢰합니다.\n\n이 고백은 단순한 긍정적 사고가 아닙니다. 욥은 자신이 하나님의 말씀을 정한 음식보다 귀히 여기며 살아왔다고 담담히 고백합니다. 그의 발은 하나님의 걸음을 따랐고, 그의 입술은 하나님의 명령을 어기지 않았습니다. 이런 삶의 토대가 있었기에 욥은 이해할 수 없는 고난 속에서도 하나님의 선하신 뜻을 신뢰할 수 있었던 것입니다.\n\n욥의 마지막 고백은 우리에게 깊은 울림을 줍니다. 그는 하나님을 두려워한다고 말하면서도, 그것이 어둠이나 흑암 때문이 아니라고 분명히 합니다. 욥이 두려워하는 것은 하나님 자체입니다. 전능하신 하나님, 자신의 뜻을 반드시 이루시는 하나님, 그분 앞에서 욥은 떨면서도 여전히 신뢰합니다. 이것이 고난 중에도 빛나는 진정한 믿음의 모습입니다.', E'오늘의 핵심\n하나님이 보이지 않는 어둠 속에서도 욥은 자신의 길을 아시는 하나님을 신뢰하며, 이 고난이 순금 같은 믿음으로 단련되는 과정임을 고백합니다.\n\n묵상 질문\n1. 하나님이 멀게만 느껴질 때, 나는 무엇을 붙잡고 있나요?\n2. 내 삶에서 "정한 음식보다 하나님의 말씀을 귀히 여기는" 모습이 있나요?\n3. 고난을 단련의 과정으로 받아들일 수 있는 믿음의 토대가 내게 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-06-22', E'욥과 엘리바스의 세 번째 논쟁 (욥기 24장)', E'욥기 24장', E'욥은 이제 더 이상 친구들의 억울한 비난에 대응하지 않습니다. 대신 그의 시선은 이 세상의 불의와 하나님의 침묵이라는 더 큰 질문으로 향합니다. "어찌하여 전능자는 때를 정해 놓지 아니하셨는고"(욥 24:1). 욥이 바라보는 세상은 참으로 어둡습니다. 땅의 경계표를 옮기고, 고아의 나귀를 빼앗고, 과부의 소를 볼모로 잡는 악인들이 판을 치고 있습니다. 가난한 자들은 들나귀처럼 광야에서 먹을 것을 찾아 헤매고, 벌거벗은 채로 추운 밤을 지새우며, 바위를 안고 비를 피합니다.\n\n욥의 묘사는 더욱 처절해집니다. 악인의 담 사이에서 기름을 짜면서도 정작 자신은 굶주리고, 술 틀을 밟으면서도 목마름에 시달리는 사람들. 성 안에서는 죽어가는 이들의 신음소리가 들리고 상한 자들이 부르짖지만, 하나님은 그들의 참상을 보지 않으시는 것 같습니다. 이것이 욥이 경험하고 있는 현실이자, 우리가 살아가는 세상의 모습이기도 합니다.\n\n그런데 욥은 단순히 세상의 불의를 고발하는 데 그치지 않습니다. 악인들의 결국을 내다봅니다. 그들은 물 위에 빨리 흘러가는 것처럼 사라질 것이며, 가뭄과 더위가 눈 녹은 물을 삼키듯 스올이 그들을 삼킬 것입니다. 모태가 그를 잊어버리고 구더기가 그를 먹을 것이며, 불의는 나무처럼 꺾일 것입니다. 비록 잠시 높아질 수 있지만, 결국은 잘려진 곡식 이삭처럼 될 것입니다.\n\n욥의 이 통찰은 우리에게 중요한 교훈을 줍니다. 하나님의 심판이 즉각적으로 나타나지 않는다고 해서 하나님이 불의를 모르시거나 방관하시는 것은 아닙니다. 하나님은 악인들의 길을 살피고 계시며, 그분의 때에 반드시 공의로운 심판을 행하실 것입니다. 우리가 살아가는 이 세상에서 불의가 승리하는 것처럼 보일 때, 선한 사람이 고통받고 악한 사람이 번영하는 것 같을 때, 욥의 이 고백을 기억해야 합니다. 하나님의 공의는 반드시 이루어질 것입니다.', E'오늘의 핵심\n욥은 세상의 불의와 하나님의 침묵이라는 현실을 직시하면서도, 악인의 번영이 일시적이며 하나님의 공의가 결국 이루어질 것임을 확신합니다.\n\n묵상 질문\n1. 내 주변에서 불의가 승리하는 것처럼 보일 때, 나는 어떻게 반응하나요?\n2. 하나님의 심판이 즉각적이지 않을 때, 그분의 공의를 여전히 신뢰할 수 있나요?\n3. 고통받는 이웃을 외면하지 않고 하나님의 마음으로 돌볼 준비가 되어 있나요?');
